classdef DenseHeightSweep
    %DENSEHEIGHTSWEEP Unregularized dense height-volume reference.
    %
    % Image arrays use (row,column); geometric pixels use one-based [x,y]
    % centers. Elevations and curvature coordinates are metres. The reference
    % path deliberately stores CPU-double volumes before tiled acceleration.
    % Traceability: algo/main.tex Secs. 10.4-10.5, 11.2-11.4, 14.6, and 15;
    % Eqs. (121)-(133), especially the recommended baseline Eq. (133).

    properties (SetAccess = private)
        CostCurve
    end

    methods
        function obj = DenseHeightSweep(costCurve)
            arguments
                costCurve (1, 1) HeightCostCurve
            end

            obj.CostCurve = costCurve;
        end

        function result = runReference(obj, z, options)
            %RUNREFERENCE Evaluate every image pixel without tiling.

            arguments
                obj (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeIncreasing, mustHaveThreeElements}
                options.Channel (1, 1) string ...
                    {mustBeMember(options.Channel, ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", "HybridZnccSpin2T3"])} ...
                    = "HybridZnccSpin2T3"
                options.Channels (1, :) string ...
                    {mustBeNonempty, mustBeMember(options.Channels, ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", ...
                    "HybridZnccSpin2T3"])} = ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", "HybridZnccSpin2T3"]
                options.StoreCostVolumes (1, 1) logical = true
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-6
                options.RequireOrientationPreserving (1, 1) logical = true
                options.ProfileOperations (1, 1) logical = false
            end

            imageSize = obj.CostCurve.Geometry.ReferenceCamera.ImageSize;
            [y, x] = ndgrid(1:imageSize(1), 1:imageSize(2));
            p = [x(:), y(:)];
            channels = unique([options.Channels, options.Channel], "stable");
            timer = tic;
            sparse = obj.CostCurve.evaluate(p, z, ...
                DeltaPixel=options.DeltaPixel, ...
                DeltaHeight=options.DeltaHeight, ...
                MinimumSupportFraction=options.MinimumSupportFraction, ...
                MinimumGradient=options.MinimumGradient, ...
                RequireOrientationPreserving= ...
                options.RequireOrientationPreserving, ...
                ProfileOperations=options.ProfileOperations, ...
                Channels=channels);
            evaluationSeconds = toc(timer);

            channel = char(options.Channel);
            cost = sparse.Costs.(channel);
            summary = DenseHeightSweep.summarize(cost, z);
            selected = summary.HeightMetres;
            correspondence = nan(size(p));
            observability = nan(size(selected));
            outputValid = summary.Valid;
            if any(outputValid)
                q = p(outputValid, :);
                h = selected(outputValid);
                [w, warpValid, inside] = ...
                    obj.CostCurve.Geometry.warp(q, h);
                [~, kappa, derivativeValid] = ...
                    obj.CostCurve.Geometry.heightDerivative( ...
                    q, h, DeltaHeight=options.DeltaHeight);
                keep = warpValid & inside & derivativeValid;
                index = find(outputValid);
                correspondence(index(keep), :) = w(keep, :);
                observability(index(keep)) = kappa(keep);
                outputValid(index(~keep)) = false;
            end
            selected(~outputValid) = NaN;
            summary.HeightMetres = selected;
            summary.Valid = outputValid;

            selectedByChannel = struct;
            costVolumeByChannel = struct;
            names = fieldnames(sparse.Costs);
            for k = 1:numel(names)
                selectedByChannel.(names{k}) = reshape( ...
                    sparse.SelectedHeight.(names{k}), imageSize);
                if options.StoreCostVolumes
                    costVolumeByChannel.(names{k}) = reshape( ...
                        sparse.Costs.(names{k}), ...
                        [imageSize, numel(z)]);
                end
            end
            sparseInfo = whos("sparse");
            n = prod(imageSize);
            if options.StoreCostVolumes
                primaryVolume = reshape(cost, [imageSize, numel(z)]);
            else
                primaryVolume = zeros([imageSize, 0]);
            end
            result = struct( ...
                "Channel", options.Channel, ...
                "ComputedChannels", sparse.ComputedChannels, ...
                "HeightLabelsMetres", z, ...
                "HeightMetres", reshape(summary.HeightMetres, imageSize), ...
                "CorrespondenceXY", reshape(correspondence, ...
                [imageSize, 2]), ...
                "Valid", reshape(summary.Valid, imageSize), ...
                "LabelIndex", reshape(summary.LabelIndex, imageSize), ...
                "BestCost", reshape(summary.BestCost, imageSize), ...
                "SecondBestCost", reshape( ...
                summary.SecondBestCost, imageSize), ...
                "PreviousLabelCost", reshape( ...
                summary.PreviousLabelCost, imageSize), ...
                "NextLabelCost", reshape( ...
                summary.NextLabelCost, imageSize), ...
                "CostMargin", reshape(summary.CostMargin, imageSize), ...
                "LocalCurvaturePerMetreSquared", reshape( ...
                summary.LocalCurvaturePerMetreSquared, imageSize), ...
                "ValidLabelCount", reshape( ...
                summary.ValidLabelCount, imageSize), ...
                "ValidLabelFraction", reshape( ...
                summary.ValidLabelFraction, imageSize), ...
                "ObservabilityPixelsPerMetre", reshape( ...
                observability, imageSize), ...
                "SelectedHeightByChannel", selectedByChannel, ...
                "CostVolume", primaryVolume, ...
                "CostVolumeByChannel", costVolumeByChannel, ...
                "StoreCostVolumes", options.StoreCostVolumes, ...
                "MarginDefinition", ...
                "second finite label cost minus best label cost", ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", ...
                obj.CostCurve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                obj.CostCurve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Interpolation", "bilinear; four samples required", ...
                "Regularization", "none", ...
                "Runtime", struct( ...
                "EvaluationSeconds", evaluationSeconds, ...
                "PixelCount", n, "LabelCount", numel(z), ...
                "PixelLabelCount", n .* numel(z), ...
                "PixelLabelsPerSecond", n .* numel(z) ...
                ./ evaluationSeconds, ...
                "SparseResultBytes", sparseInfo.bytes, ...
                "OperationProfiling", sparse.Profiling));
        end

        function result = runTiled(obj, z, options)
            %RUNTILED Serial core tiling with label-blocked sufficient stats.
            %
            % Tile cores partition reference centers. Patch samples and moving
            % correspondences are evaluated against the shared full images, so
            % neither is constrained by core boundaries. This is the serial
            % equivalence baseline required before threaded execution.

            arguments
                obj (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeIncreasing, mustHaveThreeElements}
                options.Channel (1, 1) string ...
                    {mustBeMember(options.Channel, ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", "HybridZnccSpin2T3"])} ...
                    = "HybridZnccSpin2T3"
                options.Channels (1, :) string ...
                    {mustBeNonempty, mustBeMember(options.Channels, ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", ...
                    "HybridZnccSpin2T3"])} = ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", "HybridZnccSpin2T3"]
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 16
                options.StoreCostVolumes (1, 1) logical = false
                options.UseParallel (1, 1) logical = true
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-6
                options.RequireOrientationPreserving (1, 1) logical = true
                options.ProfileOperations (1, 1) logical = false
            end

            imageSize = obj.CostCurve.Geometry.ReferenceCamera.ImageSize;
            nr = imageSize(1);
            nc = imageSize(2);
            nl = numel(z);
            names = cellstr(unique( ...
                [options.Channels, options.Channel], "stable"));
            selectedByChannel = struct;
            costVolumeByChannel = struct;
            for k = 1:numel(names)
                selectedByChannel.(names{k}) = nan(imageSize);
                if options.StoreCostVolumes
                    costVolumeByChannel.(names{k}) = nan( ...
                        [imageSize, nl]);
                end
            end
            height = nan(imageSize);
            correspondence = nan([imageSize, 2]);
            outputValid = false(imageSize);
            labelIndex = zeros(imageSize);
            best = nan(imageSize);
            second = nan(imageSize);
            previous = nan(imageSize);
            next = nan(imageSize);
            margin = nan(imageSize);
            curvature = nan(imageSize);
            validLabelCount = zeros(imageSize);
            observability = nan(imageSize);
            rowStarts = 1:options.TileSize(1):nr;
            columnStarts = 1:options.TileSize(2):nc;
            tileCount = numel(rowStarts) .* numel(columnStarts);
            bounds = zeros(tileCount, 4);
            tileIndex = 0;
            for rowStart = rowStarts
                for columnStart = columnStarts
                    tileIndex = tileIndex + 1;
                    bounds(tileIndex, :) = [rowStart, ...
                        min(rowStart + options.TileSize(1) - 1, nr), ...
                        columnStart, ...
                        min(columnStart + options.TileSize(2) - 1, nc)];
                end
            end
            maximumTilePixelCount = 0;
            maximumBlockResultBytes = 0;
            operationSeconds = zeros(1, 5);
            operationCounts = zeros(1, 9);
            timer = tic;
            tileResults = cell(tileCount, 1);
            costCurve = obj.CostCurve;
            if options.UseParallel
                pool = DenseHeightSweep.ensureThreadPool;
                numberOfWorkers = DenseHeightSweep.resolveWorkerCount( ...
                    pool, options.NumWorkers);
                % tileCount is scalar; Code Analyzer loses that fact here.
                parfor (parallelIndex = 1:tileCount, numberOfWorkers) %#ok<BDSCI>
                    tileResults{parallelIndex} = ...
                        DenseHeightSweep.evaluateTile(costCurve, ...
                        bounds(parallelIndex, :), z, options, names);
                end
                execution = "threads";
            else
                numberOfWorkers = 1;
                for serialIndex = 1:tileCount %#ok<BDSCI>
                    tileResults{serialIndex} = ...
                        DenseHeightSweep.evaluateTile(costCurve, ...
                        bounds(serialIndex, :), z, options, names);
                end
                execution = "serial";
            end

            outputInfo = whos("selectedByChannel", ...
                "costVolumeByChannel", "height", "correspondence", ...
                "outputValid", "labelIndex", "best", "second", ...
                "previous", "next", "margin", "curvature", ...
                "validLabelCount", "observability");
            outputArrayBytes = sum([outputInfo.bytes]);
            retainedInfo = whos("tileResults");
            retainedTileResultBytes = retainedInfo.bytes;

            for mergeIndex = 1:tileCount %#ok<BDSCI>
                tileResult = tileResults{mergeIndex};
                rowStart = tileResult.Bounds(1);
                rowEnd = tileResult.Bounds(2);
                columnStart = tileResult.Bounds(3);
                columnEnd = tileResult.Bounds(4);
                tileSize = [rowEnd - rowStart + 1, ...
                    columnEnd - columnStart + 1];
                tile = tileResult.Summary;
                maximumTilePixelCount = max(maximumTilePixelCount, ...
                    prod(tileSize));
                maximumBlockResultBytes = max(maximumBlockResultBytes, ...
                    tileResult.MaximumBlockResultBytes);
                operationSeconds = operationSeconds ...
                    + tileResult.OperationSeconds;
                operationCounts = operationCounts ...
                    + tileResult.OperationCounts;
                outputValid(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.Valid, tileSize);
                height(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.HeightMetres, tileSize);
                labelIndex(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.LabelIndex, tileSize);
                best(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.BestCost, tileSize);
                second(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.SecondBestCost, tileSize);
                previous(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.PreviousLabelCost, tileSize);
                next(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.NextLabelCost, tileSize);
                margin(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.CostMargin, tileSize);
                curvature(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.LocalCurvaturePerMetreSquared, tileSize);
                validLabelCount(rowStart:rowEnd, columnStart:columnEnd) = ...
                    reshape(tile.ValidLabelCount, tileSize);
                for k = 1:numel(names)
                    name = names{k};
                    selectedByChannel.(name)(rowStart:rowEnd, ...
                        columnStart:columnEnd) = reshape( ...
                        tileResult.SelectedHeightByChannel.(name), tileSize);
                    if options.StoreCostVolumes
                        costVolumeByChannel.(name)(rowStart:rowEnd, ...
                            columnStart:columnEnd, :) = reshape( ...
                            tileResult.CostVolumeByChannel.(name), ...
                            [tileSize, nl]);
                    end
                end
            end
            evaluationSeconds = toc(timer);

            index = find(outputValid);
            if ~isempty(index)
                [y, x] = ind2sub(imageSize, index);
                p = [x, y];
                h = height(index);
                [w, warpValid, inside] = ...
                    obj.CostCurve.Geometry.warp(p, h);
                [~, kappa, derivativeValid] = ...
                    obj.CostCurve.Geometry.heightDerivative( ...
                    p, h, DeltaHeight=options.DeltaHeight);
                keep = warpValid & inside & derivativeValid;
                correspondenceX = correspondence(:, :, 1);
                correspondenceY = correspondence(:, :, 2);
                correspondenceX(index(keep)) = w(keep, 1);
                correspondenceY(index(keep)) = w(keep, 2);
                correspondence(:, :, 1) = correspondenceX;
                correspondence(:, :, 2) = correspondenceY;
                observability(index(keep)) = kappa(keep);
                outputValid(index(~keep)) = false;
                height(index(~keep)) = NaN;
            end
            if options.StoreCostVolumes
                primaryVolume = costVolumeByChannel.(char(options.Channel));
            else
                primaryVolume = zeros([imageSize, 0]);
            end
            n = prod(imageSize);
            concurrentTileCount = min(numberOfWorkers, tileCount);
            maximumConcurrentBlockResultBytes = ...
                concurrentTileCount .* maximumBlockResultBytes;
            estimatedPeakTrackedBytes = outputArrayBytes ...
                + retainedTileResultBytes ...
                + maximumConcurrentBlockResultBytes;
            result = struct( ...
                "Channel", options.Channel, ...
                "ComputedChannels", string(names), ...
                "HeightLabelsMetres", z, "HeightMetres", height, ...
                "CorrespondenceXY", correspondence, "Valid", outputValid, ...
                "LabelIndex", labelIndex, "BestCost", best, ...
                "SecondBestCost", second, "CostMargin", margin, ...
                "PreviousLabelCost", previous, "NextLabelCost", next, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", validLabelCount, ...
                "ValidLabelFraction", validLabelCount ./ nl, ...
                "ObservabilityPixelsPerMetre", observability, ...
                "SelectedHeightByChannel", selectedByChannel, ...
                "CostVolume", primaryVolume, ...
                "CostVolumeByChannel", costVolumeByChannel, ...
                "StoreCostVolumes", options.StoreCostVolumes, ...
                "MarginDefinition", ...
                "second finite label cost minus best label cost", ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", ...
                obj.CostCurve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                obj.CostCurve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Interpolation", "bilinear; four samples required", ...
                "Regularization", "none", ...
                "TileBoundaryPolicy", ...
                "core centers partitioned; patch and match support unrestricted", ...
                "SpatialHaloPixels", ...
                obj.CostCurve.Reference.IntegrationRadius, ...
                "Runtime", struct( ...
                "EvaluationSeconds", evaluationSeconds, ...
                "PixelCount", n, "LabelCount", nl, ...
                "PixelLabelCount", n .* nl, ...
                "PixelLabelsPerSecond", n .* nl ./ evaluationSeconds, ...
                "TileCount", tileCount, "TileSize", options.TileSize, ...
                "RetainedTileResultCount", tileCount, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "MaximumTilePixelCount", maximumTilePixelCount, ...
                "MaximumBlockResultBytes", maximumBlockResultBytes, ...
                "OutputArrayBytes", outputArrayBytes, ...
                "RetainedTileResultBytes", retainedTileResultBytes, ...
                "MaximumConcurrentBlockResultBytes", ...
                maximumConcurrentBlockResultBytes, ...
                "MaximumConcurrentReturnedTileCount", ...
                concurrentTileCount, ...
                "EstimatedPeakTrackedBytes", estimatedPeakTrackedBytes, ...
                "MemoryDefinition", ...
                "conservative sum of retained MATLAB output/tile arrays " ...
                + "and concurrent returned cost blocks; excludes internal " ...
                + "temporaries, prepared images, pool, and runtime overhead", ...
                "OperationProfiling", struct( ...
                "Enabled", options.ProfileOperations, ...
                "OperationNames", ["ReferencePreparation", ...
                "WarpAndMovingSampling", "JacobianAndTransport", ...
                "PatchCostsT0ThroughT3", "SlopeAwareT4"], ...
                "CumulativeWorkerSeconds", operationSeconds, ...
                "OperationCountNames", ...
                ["ReferenceBilinearLocations", ...
                "MovingBilinearLocations", "WarpCalls", ...
                "WarpPointEvaluations", "WarpJacobianCalls", ...
                "WarpJacobianPointEvaluations", ...
                "HeightDerivativeCalls", ...
                "HeightDerivativePointEvaluations", ...
                "CandidatePatchLocations"], ...
                "OperationCounts", operationCounts, ...
                "Definition", ...
                "sum of elapsed operation times over tile-label blocks"), ...
                "Execution", execution, ...
                "NumWorkers", numberOfWorkers));
        end

        function result = runZnccOptimized(obj, z, options)
            %RUNZNCCOPTIMIZED Dense label-plane ZNCC CPU array path.
            %
            % Each tile carries the exact integration halo. The camera warp
            % and moving-image sampling are evaluated once per halo pixel and
            % height label; masked local moments then produce every overlapping
            % patch cost. The sparse patch path remains the reference.
            %
            % Traceability: algo/main.tex Algorithm 1, lines 4--9;
            % Eqs. (68)--(69); implementation plan Stages C1--C3.

            arguments
                obj (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeIncreasing, mustHaveThreeElements}
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.StoreCostVolumes (1, 1) logical = true
                options.UseParallel (1, 1) logical = true
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.MaximumPendingTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.Products (1, :) string ...
                    {mustBeNonempty, mustBeDenseZnccProducts} = ...
                    ["LabelIndex", "BestCost", "SecondBestCost", ...
                    "NeighborCosts", "Margin", "Curvature", ...
                    "ValidLabelCount", "Observability"]
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
            end

            imageSize = obj.CostCurve.Geometry.ReferenceCamera.ImageSize;
            nr = imageSize(1);
            nc = imageSize(2);
            nl = numel(z);
            products = unique(options.Products, "stable");
            needLabelIndex = any(products == "LabelIndex");
            needBest = any(products == "BestCost");
            needSecond = any(products == "SecondBestCost");
            needNeighbors = any(products == "NeighborCosts");
            needMargin = any(products == "Margin");
            needCurvature = any(products == "Curvature");
            needValidLabelCount = any(products == "ValidLabelCount");
            needObservability = any(products == "Observability");
            needCorrespondence = any(products == "Correspondence");
            needSelected = any(products == "SelectedHeightByChannel");
            height = nan(imageSize);
            outputValid = false(imageSize);
            labelIndex = DenseHeightSweep.optionalArray( ...
                imageSize, needLabelIndex, 0);
            best = DenseHeightSweep.optionalArray( ...
                imageSize, needBest, NaN, options.WorkingPrecision);
            second = DenseHeightSweep.optionalArray( ...
                imageSize, needSecond, NaN, options.WorkingPrecision);
            previous = DenseHeightSweep.optionalArray( ...
                imageSize, needNeighbors, NaN, options.WorkingPrecision);
            next = DenseHeightSweep.optionalArray( ...
                imageSize, needNeighbors, NaN, options.WorkingPrecision);
            margin = DenseHeightSweep.optionalArray( ...
                imageSize, needMargin, NaN, options.WorkingPrecision);
            curvature = DenseHeightSweep.optionalArray( ...
                imageSize, needCurvature, NaN, options.WorkingPrecision);
            validLabelCount = DenseHeightSweep.optionalArray( ...
                imageSize, needValidLabelCount, 0);
            if options.StoreCostVolumes
                costVolume = nan( ...
                    [imageSize, nl], options.WorkingPrecision);
            else
                costVolume = zeros( ...
                    [imageSize, 0], options.WorkingPrecision);
            end

            rowStarts = 1:options.TileSize(1):nr;
            columnStarts = 1:options.TileSize(2):nc;
            tileCount = numel(rowStarts) .* numel(columnStarts);
            bounds = zeros(tileCount, 4);
            tileIndex = 0;
            for rowStart = rowStarts
                for columnStart = columnStarts
                    tileIndex = tileIndex + 1;
                    bounds(tileIndex, :) = [rowStart, ...
                        min(rowStart + options.TileSize(1) - 1, nr), ...
                        columnStart, ...
                        min(columnStart + options.TileSize(2) - 1, nc)];
                end
            end
            if options.UseParallel
                pool = DenseHeightSweep.ensureThreadPool;
                numberOfWorkers = DenseHeightSweep.resolveWorkerCount( ...
                    pool, options.NumWorkers);
                if options.MaximumPendingTiles == 0
                    maximumPendingTiles = numberOfWorkers;
                else
                    maximumPendingTiles = options.MaximumPendingTiles;
                end
                execution = "threads-bounded";
            else
                pool = gcp("nocreate");
                numberOfWorkers = 1;
                maximumPendingTiles = 1;
                execution = "serial-dense-field";
            end
            maximumPendingTiles = min(maximumPendingTiles, tileCount);
            geometrySeconds = 0;
            samplingSeconds = 0;
            filterSeconds = 0;
            warpCalls = 0;
            warpPointEvaluations = 0;
            bilinearLocations = 0;
            localFilterOutputSamples = 0;
            maximumBlockResultBytes = 0;
            maximumRetainedTileResultBytes = 0;
            maximumRetainedTileResultCount = 0;
            timer = tic;
            for batchStart = 1:maximumPendingTiles:tileCount %#ok<BDSCI>
                batchIds = batchStart:min( ...
                    batchStart + maximumPendingTiles - 1, tileCount);
                batchCount = numel(batchIds);
                tileBatch = cell(batchCount, 1);
                if options.UseParallel
                    futures = parallel.FevalFuture.empty;
                    try
                        for k = 1:batchCount
                            futures(end + 1) = parfeval(pool, ...
                                @DenseHeightSweep.evaluateDenseZnccTile, 1, ...
                                obj.CostCurve, bounds(batchIds(k), :), ...
                                z, options); %#ok<AGROW>
                        end
                        for k = 1:batchCount
                            [completedIndex, completedTile] = ...
                                fetchNext(futures);
                            tileBatch{completedIndex} = completedTile;
                        end
                    catch exception
                        cancel(futures);
                        rethrow(exception)
                    end
                else
                    for k = 1:batchCount
                        tileBatch{k} = ...
                            DenseHeightSweep.evaluateDenseZnccTile( ...
                            obj.CostCurve, bounds(batchIds(k), :), ...
                            z, options);
                    end
                end
                retainedInfo = whos("tileBatch");
                maximumRetainedTileResultBytes = max( ...
                    maximumRetainedTileResultBytes, retainedInfo.bytes);
                maximumRetainedTileResultCount = max( ...
                    maximumRetainedTileResultCount, batchCount);
                for k = 1:batchCount
                    tile = tileBatch{k};
                    tileBounds = tile.Bounds;
                    rows = tileBounds(1):tileBounds(2);
                    columns = tileBounds(3):tileBounds(4);
                    tileSize = [numel(rows), numel(columns)];
                    summary = tile.Summary;
                    height(rows, columns) = reshape( ...
                        summary.HeightMetres, tileSize);
                    outputValid(rows, columns) = reshape( ...
                        summary.Valid, tileSize);
                    if needLabelIndex
                        labelIndex(rows, columns) = reshape( ...
                            summary.LabelIndex, tileSize);
                    end
                    if needBest
                        best(rows, columns) = reshape( ...
                            summary.BestCost, tileSize);
                    end
                    if needSecond
                        second(rows, columns) = reshape( ...
                            summary.SecondBestCost, tileSize);
                    end
                    if needNeighbors
                        previous(rows, columns) = reshape( ...
                            summary.PreviousLabelCost, tileSize);
                        next(rows, columns) = reshape( ...
                            summary.NextLabelCost, tileSize);
                    end
                    if needMargin
                        margin(rows, columns) = reshape( ...
                            summary.CostMargin, tileSize);
                    end
                    if needCurvature
                        curvature(rows, columns) = reshape( ...
                            summary.LocalCurvaturePerMetreSquared, tileSize);
                    end
                    if needValidLabelCount
                        validLabelCount(rows, columns) = reshape( ...
                            summary.ValidLabelCount, tileSize);
                    end
                    if options.StoreCostVolumes
                        costVolume(rows, columns, :) = reshape( ...
                            tile.CostVolume, [tileSize, nl]);
                    end
                    geometrySeconds = geometrySeconds ...
                        + tile.GeometrySeconds;
                    samplingSeconds = samplingSeconds ...
                        + tile.SamplingSeconds;
                    filterSeconds = filterSeconds + tile.FilterSeconds;
                    warpCalls = warpCalls + tile.WarpCalls;
                    warpPointEvaluations = warpPointEvaluations ...
                        + tile.WarpPointEvaluations;
                    bilinearLocations = bilinearLocations ...
                        + tile.BilinearLocations;
                    localFilterOutputSamples = localFilterOutputSamples ...
                        + tile.LocalFilterOutputSamples;
                    maximumBlockResultBytes = max( ...
                        maximumBlockResultBytes, ...
                        tile.MaximumBlockResultBytes);
                end
            end
            evaluationSeconds = toc(timer);

            selectedHeight = height;
            inputValid = outputValid & isfinite(height);
            index = find(inputValid);
            outputValid(:) = false;
            if needCorrespondence
                correspondence = nan([imageSize, 2]);
            else
                correspondence = zeros([imageSize, 0]);
            end
            if needObservability
                observability = nan(imageSize);
            else
                observability = zeros([imageSize, 0]);
            end
            if ~isempty(index)
                [y, x] = ind2sub(imageSize, index);
                p = [x, y];
                h = height(index);
                [w, projectionValid, inside] = ...
                    obj.CostCurve.Geometry.warp(p, h);
                [~, kappa, derivativeValid] = ...
                    obj.CostCurve.Geometry.heightDerivative( ...
                    p, h, DeltaHeight=options.DeltaHeight);
                keep = projectionValid & inside & derivativeValid;
                outputValid(index(keep)) = true;
                if needCorrespondence
                    wx = correspondence(:, :, 1);
                    wy = correspondence(:, :, 2);
                    wx(index(keep)) = w(keep, 1);
                    wy(index(keep)) = w(keep, 2);
                    correspondence(:, :, 1) = wx;
                    correspondence(:, :, 2) = wy;
                end
                if needObservability
                    observability(index(keep)) = kappa(keep);
                end
            end
            height(~outputValid) = NaN;
            if needSelected
                selected = struct("Zncc", selectedHeight);
            else
                selected = struct;
            end
            if options.StoreCostVolumes
                costByChannel = struct("Zncc", costVolume);
            else
                costByChannel = struct;
            end
            outputInfo = whos("height", "outputValid", "labelIndex", ...
                "best", "second", "previous", "next", "margin", ...
                "curvature", "validLabelCount", "costVolume", ...
                "correspondence", "observability", "selected");
            outputArrayBytes = sum([outputInfo.bytes]);
            result = struct( ...
                "Channel", "Zncc", ...
                "ComputedChannels", "Zncc", ...
                "HeightLabelsMetres", z, ...
                "HeightMetres", height, ...
                "CorrespondenceXY", correspondence, ...
                "Valid", outputValid, ...
                "LabelIndex", labelIndex, ...
                "BestCost", best, ...
                "SecondBestCost", second, ...
                "CostMargin", margin, ...
                "PreviousLabelCost", previous, ...
                "NextLabelCost", next, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", validLabelCount, ...
                "ValidLabelFraction", ...
                DenseHeightSweep.optionalFraction( ...
                validLabelCount, needValidLabelCount, nl), ...
                "ObservabilityPixelsPerMetre", ...
                observability, ...
                "SelectedHeightByChannel", selected, ...
                "CostVolume", costVolume, ...
                "CostVolumeByChannel", costByChannel, ...
                "StoreCostVolumes", options.StoreCostVolumes, ...
                "Products", ["Height", "Validity", products], ...
                "MarginDefinition", ...
                "second finite label cost minus best label cost", ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", ...
                obj.CostCurve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                obj.CostCurve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Interpolation", ...
                "vectorized bilinear; all nonzero-weight samples required", ...
                "Regularization", "none", ...
                "TileBoundaryPolicy", ...
                "core centers partitioned; exact integration halo", ...
                "SpatialHaloPixels", ...
                obj.CostCurve.Reference.IntegrationRadius, ...
                "Runtime", struct( ...
                "EvaluationSeconds", evaluationSeconds, ...
                "PixelCount", prod(imageSize), ...
                "LabelCount", nl, ...
                "PixelLabelCount", prod(imageSize) .* nl, ...
                "PixelLabelsPerSecond", ...
                prod(imageSize) .* nl ./ evaluationSeconds, ...
                "TileCount", tileCount, ...
                "TileSize", options.TileSize, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "GeometrySeconds", geometrySeconds, ...
                "BilinearSamplingSeconds", samplingSeconds, ...
                "LocalFilterSeconds", filterSeconds, ...
                "WarpCalls", warpCalls, ...
                "WarpPointEvaluations", warpPointEvaluations, ...
                "BilinearSampleLocations", bilinearLocations, ...
                "LocalFilterOutputSamples", ...
                localFilterOutputSamples, ...
                "LocalFilterSamplesPerSecond", ...
                localFilterOutputSamples ./ max(filterSeconds, eps), ...
                "MaximumBlockResultBytes", maximumBlockResultBytes, ...
                "OutputArrayBytes", outputArrayBytes, ...
                "RetainedTileResultBytes", ...
                maximumRetainedTileResultBytes, ...
                "RetainedTileResultCount", ...
                maximumRetainedTileResultCount, ...
                "MaximumPendingTiles", maximumPendingTiles, ...
                "Execution", execution, ...
                "NumWorkers", numberOfWorkers, ...
                "Precision", options.WorkingPrecision, ...
                "SourcePrecision", ...
                obj.CostCurve.Reference.WorkingPrecision));
        end

        function result = runZnccPlannedTiles(obj, plan, options)
            %RUNZNCCPLANNEDTILES Evaluate one exact label vector per tile.
            %
            % Tile cores must form an exact, nonoverlapping partition of the
            % reference image. Each core retains the full ZNCC integration
            % halo, so equal per-tile label vectors are numerically identical
            % to RUNZNCCOPTIMIZED with the same core bounds.
            %
            % Traceability: algo/main.tex Algorithm 1, lines 4--9 and
            % Eqs. (68)--(69); implementation plan C1 milestone 4.

            arguments
                obj (1, 1) DenseHeightSweep
                plan table {mustBePlannedZnccTiles}
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.StoreCostVolumes (1, 1) logical = false
                options.GroupIdenticalBands (1, 1) logical = false
                options.MaximumBandTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 4
                options.UseParallel (1, 1) logical = true
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.MaximumPendingTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.Products (1, :) string ...
                    {mustBeNonempty, mustBePlannedZnccProducts} = ...
                    ["TileIndex", "LabelCount", "LabelIndex", ...
                    "BestCost", "SecondBestCost", "NeighborCosts", ...
                    "Margin", "Curvature", "ValidLabelCount", ...
                    "Observability", "Correspondence", ...
                    "SelectedHeightByChannel"]
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.RequireCompletePartition (1, 1) logical = true
                options.ReplaceStoredTiles (1, 1) logical = false
                options.CostStore ...
                    {mustBeOptionalHeightTileStore} = []
            end

            imageSize = obj.CostCurve.Geometry.ReferenceCamera.ImageSize;
            products = unique(options.Products, "stable");
            needTileIndex = any(products == "TileIndex");
            exposeLabelCount = any(products == "LabelCount");
            needLabelIndex = any(products == "LabelIndex");
            needBest = any(products == "BestCost");
            needSecond = any(products == "SecondBestCost");
            needNeighbors = any(products == "NeighborCosts");
            needMargin = any(products == "Margin");
            needCurvature = any(products == "Curvature");
            needValidLabelCount = any(products == "ValidLabelCount");
            needLabelCount = exposeLabelCount || needValidLabelCount;
            needObservability = any(products == "Observability");
            needCorrespondence = any(products == "Correspondence");
            needSelected = any(products == "SelectedHeightByChannel");
            hasCostStore = ~isempty(options.CostStore);
            if hasCostStore
                storeIndices = DenseHeightSweep.validateTileStoreRequest( ...
                    options.CostStore, plan, imageSize, ...
                    options.WorkingPrecision, options.ReplaceStoredTiles);
            else
                storeIndices = zeros(height(plan), 1);
            end
            workerOptions = options;
            workerOptions = rmfield(workerOptions, ...
                ["CostStore", "ReplaceStoredTiles", ...
                "RequireCompletePartition", "GroupIdenticalBands", ...
                "MaximumBandTiles"]);
            workerOptions.StoreCostVolumes = ...
                options.StoreCostVolumes || hasCostStore;
            tileCount = height(plan);
            bandGroups = DenseHeightSweep.groupIdenticalBands( ...
                plan, options.GroupIdenticalBands, ...
                options.MaximumBandTiles);
            bandCount = numel(bandGroups);
            bounds = [plan.RowStart, plan.RowEnd, ...
                plan.ColumnStart, plan.ColumnEnd];
            tileIndex = DenseHeightSweep.optionalArray( ...
                imageSize, needTileIndex, 0, "uint32");
            labelCount = DenseHeightSweep.optionalArray( ...
                imageSize, needLabelCount, 0);
            if needTileIndex
                covered = false([imageSize, 0]);
            else
                covered = false(imageSize);
            end
            pixelLabelCount = 0;
            for k = 1:tileCount
                b = bounds(k, :);
                if b(2) > imageSize(1) || b(4) > imageSize(2)
                    error("DenseHeightSweep:TileOutsideReference", ...
                        "Planned tile %d exceeds the reference image.", ...
                        plan.Tile(k));
                end
                rr = b(1):b(2);
                cc = b(3):b(4);
                if (needTileIndex && any(tileIndex(rr, cc) ~= 0, "all")) ...
                        || (~needTileIndex && any(covered(rr, cc), "all"))
                    error("DenseHeightSweep:OverlappingTileCores", ...
                        "Planned tile %d overlaps an earlier tile core.", ...
                        plan.Tile(k));
                end
                if needTileIndex
                    tileIndex(rr, cc) = uint32(plan.Tile(k));
                else
                    covered(rr, cc) = true;
                end
                nl = numel(plan.HeightLabelsMetres{k});
                if needLabelCount
                    labelCount(rr, cc) = nl;
                end
                pixelLabelCount = pixelLabelCount + numel(rr) .* numel(cc) .* nl;
            end
            incomplete = (needTileIndex && any(tileIndex == 0, "all")) ...
                || (~needTileIndex && any(~covered, "all"));
            if options.RequireCompletePartition && incomplete
                error("DenseHeightSweep:IncompleteTilePartition", ...
                    "Planned tile cores must cover every reference pixel.");
            end

            heightMap = nan(imageSize);
            candidateValid = false(imageSize);
            labelIndex = DenseHeightSweep.optionalArray( ...
                imageSize, needLabelIndex, 0);
            best = DenseHeightSweep.optionalArray( ...
                imageSize, needBest, NaN, options.WorkingPrecision);
            second = DenseHeightSweep.optionalArray( ...
                imageSize, needSecond, NaN, options.WorkingPrecision);
            previous = DenseHeightSweep.optionalArray( ...
                imageSize, needNeighbors, NaN, options.WorkingPrecision);
            next = DenseHeightSweep.optionalArray( ...
                imageSize, needNeighbors, NaN, options.WorkingPrecision);
            margin = DenseHeightSweep.optionalArray( ...
                imageSize, needMargin, NaN, options.WorkingPrecision);
            curvature = DenseHeightSweep.optionalArray( ...
                imageSize, needCurvature, NaN, options.WorkingPrecision);
            validLabelCount = DenseHeightSweep.optionalArray( ...
                imageSize, needValidLabelCount, 0);
            if options.StoreCostVolumes
                costVolumes = cell(tileCount, 1);
            else
                costVolumes = cell(0, 1);
            end

            if options.UseParallel
                pool = DenseHeightSweep.ensureThreadPool;
                numberOfWorkers = DenseHeightSweep.resolveWorkerCount( ...
                    pool, options.NumWorkers);
                if options.MaximumPendingTiles == 0
                    maximumPendingTiles = numberOfWorkers;
                else
                    maximumPendingTiles = options.MaximumPendingTiles;
                end
                execution = "threads-bounded";
            else
                numberOfWorkers = 1;
                maximumPendingTiles = 1;
                execution = "serial-dense-field";
            end
            maximumPendingTiles = min(maximumPendingTiles, bandCount);

            geometrySeconds = 0;
            samplingSeconds = 0;
            filterSeconds = 0;
            warpCalls = 0;
            warpPointEvaluations = 0;
            bilinearLocations = 0;
            localFilterOutputSamples = 0;
            maximumBlockResultBytes = 0;
            maximumRetainedTileResultBytes = 0;
            maximumRetainedTileResultCount = 0;
            timer = tic;
            for batchStart = 1:maximumPendingTiles:bandCount
                batchIds = batchStart:min( ...
                    batchStart + maximumPendingTiles - 1, bandCount);
                batchCount = numel(batchIds);
                tileBatch = cell(batchCount, 1);
                if options.UseParallel
                    futures = parallel.FevalFuture.empty;
                    try
                        for k = 1:batchCount
                            ids = bandGroups{batchIds(k)};
                            b = [min(plan.RowStart(ids)), ...
                                max(plan.RowEnd(ids)), ...
                                min(plan.ColumnStart(ids)), ...
                                max(plan.ColumnEnd(ids))];
                            z = double(plan.HeightLabelsMetres{ids(1)});
                            futures(end + 1) = parfeval(pool, ...
                                @DenseHeightSweep.evaluateDenseZnccTile, 1, ...
                                obj.CostCurve, b, z, ...
                                workerOptions); ...
                                %#ok<AGROW>
                        end
                        for k = 1:batchCount
                            [completedIndex, completedTile] = ...
                                fetchNext(futures);
                            tileBatch{completedIndex} = completedTile;
                        end
                    catch exception
                        cancel(futures);
                        rethrow(exception)
                    end
                else
                    for k = 1:batchCount
                        ids = bandGroups{batchIds(k)};
                        b = [min(plan.RowStart(ids)), ...
                            max(plan.RowEnd(ids)), ...
                            min(plan.ColumnStart(ids)), ...
                            max(plan.ColumnEnd(ids))];
                        z = double(plan.HeightLabelsMetres{ids(1)});
                        tileBatch{k} = ...
                            DenseHeightSweep.evaluateDenseZnccTile( ...
                            obj.CostCurve, b, z, workerOptions);
                    end
                end
                retainedInfo = whos("tileBatch");
                maximumRetainedTileResultBytes = max( ...
                    maximumRetainedTileResultBytes, retainedInfo.bytes);
                maximumRetainedTileResultCount = max( ...
                    maximumRetainedTileResultCount, batchCount);
                for k = 1:batchCount
                    tile = tileBatch{k};
                    b = tile.Bounds;
                    bsz = [b(2) - b(1) + 1, b(4) - b(3) + 1];
                    summary = tile.Summary;
                    h = reshape(summary.HeightMetres, bsz);
                    v = reshape(summary.Valid, bsz);
                    li = reshape(summary.LabelIndex, bsz);
                    bc = reshape(summary.BestCost, bsz);
                    sc = reshape(summary.SecondBestCost, bsz);
                    pc = reshape(summary.PreviousLabelCost, bsz);
                    nc = reshape(summary.NextLabelCost, bsz);
                    cm = reshape(summary.CostMargin, bsz);
                    cu = reshape( ...
                        summary.LocalCurvaturePerMetreSquared, bsz);
                    nv = reshape(summary.ValidLabelCount, bsz);
                    if workerOptions.StoreCostVolumes
                        ids = bandGroups{batchIds(k)};
                        nl = numel(plan.HeightLabelsMetres{ids(1)});
                        bandCost = reshape(tile.CostVolume, [bsz, nl]);
                    else
                        ids = bandGroups{batchIds(k)};
                        bandCost = zeros([bsz, 0], ...
                            options.WorkingPrecision);
                    end
                    for j = 1:numel(ids)
                        id = ids(j);
                        rr = plan.RowStart(id):plan.RowEnd(id);
                        cc = plan.ColumnStart(id):plan.ColumnEnd(id);
                        lr = rr - b(1) + 1;
                        lc = cc - b(3) + 1;
                        heightMap(rr, cc) = h(lr, lc);
                        candidateValid(rr, cc) = v(lr, lc);
                        if needLabelIndex
                            labelIndex(rr, cc) = li(lr, lc);
                        end
                        if needBest
                            best(rr, cc) = bc(lr, lc);
                        end
                        if needSecond
                            second(rr, cc) = sc(lr, lc);
                        end
                        if needNeighbors
                            previous(rr, cc) = pc(lr, lc);
                            next(rr, cc) = nc(lr, lc);
                        end
                        if needMargin
                            margin(rr, cc) = cm(lr, lc);
                        end
                        if needCurvature
                            curvature(rr, cc) = cu(lr, lc);
                        end
                        if needValidLabelCount
                            validLabelCount(rr, cc) = nv(lr, lc);
                        end
                        if workerOptions.StoreCostVolumes
                            tileCost = bandCost(lr, lc, :);
                        else
                            tileCost = zeros([numel(rr), numel(cc), 0], ...
                                options.WorkingPrecision);
                        end
                        if options.StoreCostVolumes
                            costVolumes{id} = tileCost;
                        end
                        if hasCostStore
                            if options.ReplaceStoredTiles
                                options.CostStore.replaceTiles( ...
                                    storeIndices(id), plan(id, :), ...
                                    {tileCost});
                            else
                                options.CostStore.writeTiles( ...
                                    storeIndices(id), {tileCost});
                            end
                        end
                    end
                    geometrySeconds = geometrySeconds + tile.GeometrySeconds;
                    samplingSeconds = samplingSeconds + tile.SamplingSeconds;
                    filterSeconds = filterSeconds + tile.FilterSeconds;
                    warpCalls = warpCalls + tile.WarpCalls;
                    warpPointEvaluations = warpPointEvaluations ...
                        + tile.WarpPointEvaluations;
                    bilinearLocations = bilinearLocations ...
                        + tile.BilinearLocations;
                    localFilterOutputSamples = localFilterOutputSamples ...
                        + tile.LocalFilterOutputSamples;
                    maximumBlockResultBytes = max( ...
                        maximumBlockResultBytes, ...
                        tile.MaximumBlockResultBytes);
                end
            end
            evaluationSeconds = toc(timer);

            if needSelected
                selectedHeight = heightMap;
            else
                selectedHeight = zeros([imageSize, 0]);
            end
            projectionProducts = strings(1, 0);
            if needCorrespondence
                projectionProducts(end + 1) = "Correspondence";
            end
            if needObservability
                projectionProducts(end + 1) = "Observability";
            end
            projection = obj.projectHeightMap( ...
                heightMap, candidateValid, ...
                DeltaHeight=options.DeltaHeight, ...
                Products=projectionProducts);
            heightMap = projection.HeightMetres;
            outputInfo = whos("heightMap", "candidateValid", ...
                "labelIndex", "best", "second", "previous", "next", ...
                "margin", "curvature", "validLabelCount", "tileIndex", ...
                "labelCount", "costVolumes");
            outputArrayBytes = sum([outputInfo.bytes]);
            if options.RequireCompletePartition
                boundaryPolicy = ...
                    "nonoverlapping cores; exact integration halo; matches may cross cores";
            else
                boundaryPolicy = ...
                    "selected nonoverlapping cores; exact integration halo; unselected pixels invalid";
            end
            if needSelected
                selected = struct("Zncc", selectedHeight);
            else
                selected = struct;
            end
            if exposeLabelCount
                labelCountResult = labelCount;
            else
                labelCountResult = zeros([imageSize, 0]);
            end
            result = struct( ...
                "Channel", "Zncc", ...
                "ComputedChannels", "Zncc", ...
                "HeightLabelsMetres", zeros(1, 0), ...
                "HeightLabelsByTile", {plan.HeightLabelsMetres}, ...
                "TilePlan", plan, ...
                "BandGroups", {bandGroups}, ...
                "TileIndex", tileIndex, ...
                "LabelCount", labelCountResult, ...
                "HeightMetres", heightMap, ...
                "CorrespondenceXY", projection.CorrespondenceXY, ...
                "Valid", projection.Valid, ...
                "LabelIndex", labelIndex, ...
                "BestCost", best, ...
                "SecondBestCost", second, ...
                "CostMargin", margin, ...
                "PreviousLabelCost", previous, ...
                "NextLabelCost", next, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", validLabelCount, ...
                "ValidLabelFraction", ...
                DenseHeightSweep.optionalFraction( ...
                validLabelCount, needValidLabelCount, labelCount), ...
                "ObservabilityPixelsPerMetre", ...
                projection.ObservabilityPixelsPerMetre, ...
                "SelectedHeightByChannel", selected, ...
                "CostVolume", zeros([imageSize, 0], ...
                options.WorkingPrecision), ...
                "CostVolumeByChannel", struct, ...
                "CostVolumesByTile", {costVolumes}, ...
                "CostStore", options.CostStore, ...
                "StoreCostVolumes", options.StoreCostVolumes, ...
                "Products", ["Height", "Validity", products], ...
                "MarginDefinition", ...
                "second finite tile-label cost minus best tile-label cost", ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", ...
                obj.CostCurve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                obj.CostCurve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Interpolation", ...
                "vectorized bilinear; all nonzero-weight samples required", ...
                "Regularization", "none", ...
                "TileBoundaryPolicy", boundaryPolicy, ...
                "CompletePartition", options.RequireCompletePartition, ...
                "SpatialHaloPixels", ...
                obj.CostCurve.Reference.IntegrationRadius, ...
                "Approximation", ...
                "one exact common height-label vector per tile", ...
                "Runtime", struct( ...
                "EvaluationSeconds", evaluationSeconds, ...
                "PixelCount", prod(imageSize), ...
                "TileCount", tileCount, ...
                "BandCount", bandCount, ...
                "GroupedTileCount", tileCount - bandCount, ...
                "MaximumBandTileCount", ...
                max(cellfun(@numel, bandGroups)), ...
                "GroupIdenticalBands", options.GroupIdenticalBands, ...
                "MaximumBandTiles", options.MaximumBandTiles, ...
                "PixelLabelCount", pixelLabelCount, ...
                "PixelLabelsPerSecond", ...
                pixelLabelCount ./ evaluationSeconds, ...
                "MinimumLabelCount", min(plan.LabelCount), ...
                "MedianLabelCount", median(plan.LabelCount), ...
                "MaximumLabelCount", max(plan.LabelCount), ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "GeometrySeconds", geometrySeconds, ...
                "BilinearSamplingSeconds", samplingSeconds, ...
                "LocalFilterSeconds", filterSeconds, ...
                "WarpCalls", warpCalls, ...
                "WarpPointEvaluations", warpPointEvaluations, ...
                "BilinearSampleLocations", bilinearLocations, ...
                "LocalFilterOutputSamples", localFilterOutputSamples, ...
                "MaximumBlockResultBytes", maximumBlockResultBytes, ...
                "OutputArrayBytes", outputArrayBytes, ...
                "RetainedTileResultBytes", ...
                maximumRetainedTileResultBytes, ...
                "RetainedTileResultCount", ...
                maximumRetainedTileResultCount, ...
                "MaximumPendingTiles", maximumPendingTiles, ...
                "Execution", execution, ...
                "NumWorkers", numberOfWorkers, ...
                "Precision", options.WorkingPrecision, ...
                "SourcePrecision", ...
                obj.CostCurve.Reference.WorkingPrecision, ...
                "CostStoreStatistics", ...
                DenseHeightSweep.optionalTileStoreStatistics( ...
                options.CostStore)));
        end

        function result = runT3Optimized(obj, z, options)
            %RUNT3OPTIMIZED Dense exact-transport spin-2 T3 path.
            % Traceability: algo/main.tex Eqs. (22), (25), and (58),
            % Algorithm 1 lines 4--9; implementation plan Stage C6.

            arguments
                obj (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeIncreasing, mustHaveThreeElements}
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 4
                options.StoreCostVolumes (1, 1) logical = false
                options.UseParallel (1, 1) logical = true
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.MaximumPendingTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.Products (1, :) string ...
                    {mustBeNonempty, mustBeDenseT3Products} = ...
                    ["LabelIndex", "BestCost", "Margin", "Curvature", ...
                    "Confidence", "Support", "Observability"]
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-6
                options.RequireOrientationPreserving (1, 1) logical = true
            end

            if ~obj.CostCurve.Reference.GradientsPrepared ...
                    || ~obj.CostCurve.Moving.GradientsPrepared
                error("DenseHeightSweep:GradientsNotPrepared", ...
                    "Dense T3 requires gradient preparation.");
            end
            imageSize = ...
                obj.CostCurve.Geometry.ReferenceCamera.ImageSize;
            nr = imageSize(1);
            nc = imageSize(2);
            nl = numel(z);
            precision = options.WorkingPrecision;
            products = unique(options.Products, "stable");
            needLabel = any(products == "LabelIndex");
            needBest = any(products == "BestCost");
            needSecond = any(products == "SecondBestCost");
            needNeighbors = any(products == "NeighborCosts");
            needMargin = any(products == "Margin");
            needCurvature = any(products == "Curvature");
            needCount = any(products == "ValidLabelCount");
            needConfidence = any(products == "Confidence");
            needSupport = any(products == "Support");
            needCorrespondence = any(products == "Correspondence");
            needObservability = any(products == "Observability");
            height = nan(imageSize);
            valid = false(imageSize);
            labelIndex = DenseHeightSweep.optionalArray( ...
                imageSize, needLabel, 0);
            best = DenseHeightSweep.optionalArray( ...
                imageSize, needBest, NaN, precision);
            second = DenseHeightSweep.optionalArray( ...
                imageSize, needSecond, NaN, precision);
            previous = DenseHeightSweep.optionalArray( ...
                imageSize, needNeighbors, NaN, precision);
            next = DenseHeightSweep.optionalArray( ...
                imageSize, needNeighbors, NaN, precision);
            margin = DenseHeightSweep.optionalArray( ...
                imageSize, needMargin, NaN, precision);
            curvature = DenseHeightSweep.optionalArray( ...
                imageSize, needCurvature, NaN, precision);
            count = DenseHeightSweep.optionalArray( ...
                imageSize, needCount, 0);
            confidence = DenseHeightSweep.optionalArray( ...
                imageSize, needConfidence, NaN, precision);
            support = DenseHeightSweep.optionalArray( ...
                imageSize, needSupport, NaN, precision);
            if options.StoreCostVolumes
                costVolume = nan([imageSize, nl], precision);
            else
                costVolume = zeros([imageSize, 0], precision);
            end

            rowStarts = 1:options.TileSize(1):nr;
            columnStarts = 1:options.TileSize(2):nc;
            bounds = zeros(numel(rowStarts) .* numel(columnStarts), 4);
            tileIndex = 0;
            for rowStart = rowStarts
                for columnStart = columnStarts
                    tileIndex = tileIndex + 1;
                    bounds(tileIndex, :) = [rowStart, ...
                        min(rowStart + options.TileSize(1) - 1, nr), ...
                        columnStart, ...
                        min(columnStart + options.TileSize(2) - 1, nc)];
                end
            end
            tileCount = size(bounds, 1);
            if options.UseParallel
                pool = DenseHeightSweep.ensureThreadPool;
                numberOfWorkers = DenseHeightSweep.resolveWorkerCount( ...
                    pool, options.NumWorkers);
                if options.MaximumPendingTiles == 0
                    maximumPendingTiles = numberOfWorkers;
                else
                    maximumPendingTiles = options.MaximumPendingTiles;
                end
                execution = "threads-bounded-dense-t3";
            else
                pool = gcp("nocreate");
                numberOfWorkers = 1;
                maximumPendingTiles = 1;
                execution = "serial-dense-t3";
            end
            maximumPendingTiles = min(maximumPendingTiles, tileCount);
            geometrySeconds = 0;
            samplingSeconds = 0;
            filterSeconds = 0;
            maximumBlockResultBytes = 0;
            maximumReturnedTileBytes = 0;
            timer = tic;
            for batchStart = 1:maximumPendingTiles:tileCount
                ids = batchStart:min( ...
                    batchStart + maximumPendingTiles - 1, tileCount);
                tiles = cell(numel(ids), 1);
                if options.UseParallel
                    futures = parallel.FevalFuture.empty;
                    try
                        for k = 1:numel(ids)
                            futures(end + 1) = parfeval(pool, ...
                                @DenseHeightSweep.evaluateDenseT3Tile, 1, ...
                                obj.CostCurve, bounds(ids(k), :), ...
                                z, options); %#ok<AGROW>
                        end
                        for k = 1:numel(ids)
                            [completed, tile] = fetchNext(futures);
                            tiles{completed} = tile;
                        end
                    catch exception
                        cancel(futures);
                        rethrow(exception)
                    end
                else
                    for k = 1:numel(ids)
                        tiles{k} = DenseHeightSweep.evaluateDenseT3Tile( ...
                            obj.CostCurve, bounds(ids(k), :), z, options);
                    end
                end
                returned = whos("tiles");
                maximumReturnedTileBytes = max( ...
                    maximumReturnedTileBytes, returned.bytes);
                for k = 1:numel(tiles)
                    tile = tiles{k};
                    b = tile.Bounds;
                    rows = b(1):b(2);
                    columns = b(3):b(4);
                    tileSize = [numel(rows), numel(columns)];
                    summary = tile.Summary;
                    height(rows, columns) = reshape( ...
                        summary.HeightMetres, tileSize);
                    valid(rows, columns) = reshape( ...
                        summary.Valid, tileSize);
                    if needLabel
                        labelIndex(rows, columns) = reshape( ...
                            summary.LabelIndex, tileSize);
                    end
                    if needBest
                        best(rows, columns) = reshape( ...
                            summary.BestCost, tileSize);
                    end
                    if needSecond
                        second(rows, columns) = reshape( ...
                            summary.SecondBestCost, tileSize);
                    end
                    if needNeighbors
                        previous(rows, columns) = reshape( ...
                            summary.PreviousLabelCost, tileSize);
                        next(rows, columns) = reshape( ...
                            summary.NextLabelCost, tileSize);
                    end
                    if needMargin
                        margin(rows, columns) = reshape( ...
                            summary.CostMargin, tileSize);
                    end
                    if needCurvature
                        curvature(rows, columns) = reshape( ...
                            summary.LocalCurvaturePerMetreSquared, tileSize);
                    end
                    if needCount
                        count(rows, columns) = reshape( ...
                            summary.ValidLabelCount, tileSize);
                    end
                    if needConfidence
                        confidence(rows, columns) = reshape( ...
                            tile.BestConfidence, tileSize);
                    end
                    if needSupport
                        support(rows, columns) = reshape( ...
                            tile.BestSupport, tileSize);
                    end
                    if options.StoreCostVolumes
                        costVolume(rows, columns, :) = reshape( ...
                            tile.CostVolume, [tileSize, nl]);
                    end
                    geometrySeconds = geometrySeconds ...
                        + tile.GeometrySeconds;
                    samplingSeconds = samplingSeconds ...
                        + tile.SamplingSeconds;
                    filterSeconds = filterSeconds + tile.FilterSeconds;
                    maximumBlockResultBytes = max( ...
                        maximumBlockResultBytes, ...
                        tile.MaximumBlockResultBytes);
                end
            end
            evaluationSeconds = toc(timer);

            inputValid = valid & isfinite(height);
            valid(:) = false;
            if needCorrespondence
                correspondence = nan([imageSize, 2]);
            else
                correspondence = zeros([imageSize, 0]);
            end
            if needObservability
                observability = nan(imageSize);
            else
                observability = zeros([imageSize, 0]);
            end
            selected = find(inputValid);
            if ~isempty(selected)
                [y, x] = ind2sub(imageSize, selected);
                p = [x, y];
                h = height(selected);
                [w, projectionValid, inside] = ...
                    obj.CostCurve.Geometry.warp(p, h);
                [~, kappa, derivativeValid] = ...
                    obj.CostCurve.Geometry.heightDerivative( ...
                    p, h, DeltaHeight=options.DeltaHeight);
                keep = projectionValid & inside & derivativeValid;
                valid(selected(keep)) = true;
                if needCorrespondence
                    wx = correspondence(:, :, 1);
                    wy = correspondence(:, :, 2);
                    wx(selected(keep)) = w(keep, 1);
                    wy(selected(keep)) = w(keep, 2);
                    correspondence(:, :, 1) = wx;
                    correspondence(:, :, 2) = wy;
                end
                if needObservability
                    observability(selected(keep)) = kappa(keep);
                end
            end
            height(~valid) = NaN;
            outputInfo = whos("height", "valid", "labelIndex", ...
                "best", "second", "previous", "next", "margin", ...
                "curvature", "count", "confidence", "support", ...
                "costVolume", "correspondence", "observability");
            result = struct( ...
                "Channel", "Spin2T3", ...
                "ComputedChannels", "Spin2T3", ...
                "HeightLabelsMetres", z, ...
                "HeightMetres", height, ...
                "CorrespondenceXY", correspondence, ...
                "Valid", valid, ...
                "LabelIndex", labelIndex, ...
                "BestCost", best, ...
                "SecondBestCost", second, ...
                "CostMargin", margin, ...
                "PreviousLabelCost", previous, ...
                "NextLabelCost", next, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", count, ...
                "ValidLabelFraction", ...
                DenseHeightSweep.optionalFraction(count, needCount, nl), ...
                "Spin2T3Confidence", confidence, ...
                "SupportFraction", support, ...
                "ObservabilityPixelsPerMetre", observability, ...
                "CostVolume", costVolume, ...
                "CostVolumeByChannel", ...
                DenseHeightSweep.optionalCostStruct( ...
                costVolume, options.StoreCostVolumes, "Spin2T3"), ...
                "StoreCostVolumes", options.StoreCostVolumes, ...
                "Products", ["Height", "Validity", products], ...
                "Regularization", "none", ...
                "Transport", "exact local A^T at every halo sample", ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", ...
                obj.CostCurve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                obj.CostCurve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Runtime", struct( ...
                "EvaluationSeconds", evaluationSeconds, ...
                "PixelLabelCount", prod(imageSize) .* nl, ...
                "PixelLabelsPerSecond", prod(imageSize) .* nl ...
                ./ evaluationSeconds, ...
                "TileCount", tileCount, ...
                "TileSize", options.TileSize, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "GeometryAndJacobianSeconds", geometrySeconds, ...
                "GradientSamplingSeconds", samplingSeconds, ...
                "DescriptorFilterSeconds", filterSeconds, ...
                "MaximumBlockResultBytes", maximumBlockResultBytes, ...
                "MaximumReturnedTileBytes", maximumReturnedTileBytes, ...
                "OutputArrayBytes", sum([outputInfo.bytes]), ...
                "MaximumPendingTiles", maximumPendingTiles, ...
                "Execution", execution, ...
                "NumWorkers", numberOfWorkers, ...
                "Precision", precision, ...
                "GeometryPrecision", "double"));
        end

        function result = writeZnccStore(obj, z, store, options)
            %WRITEZNCCSTORE Generate dense ZNCC once into row slabs.
            % Raw WTA, neighbor, margin, and curvature state is updated while
            % each tile result is merged. No full cost volume is returned.
            % Traceability: algo/main.tex Eqs. (68)--(69), Algorithm 1;
            % implementation plan Stage C5.

            arguments
                obj (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeIncreasing, mustHaveThreeElements}
                store (1, 1) HeightVolumeStore ...
                    {mustBeWritableZnccStore(store, obj, z)}
                options.RowSlabRows (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 128
                options.TileColumns (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 256
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.UseParallel (1, 1) logical = true
                options.NumWorkers (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.MaximumPendingTiles (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
            end

            imageSize = ...
                obj.CostCurve.Geometry.ReferenceCamera.ImageSize;
            nr = imageSize(1);
            nc = imageSize(2);
            nl = numel(z);
            precision = store.Precision;
            height = nan(imageSize);
            valid = false(imageSize);
            labelIndex = zeros(imageSize);
            best = nan(imageSize, precision);
            second = nan(imageSize, precision);
            previous = nan(imageSize, precision);
            next = nan(imageSize, precision);
            margin = nan(imageSize, precision);
            curvature = nan(imageSize, precision);
            validLabelCount = zeros(imageSize);
            if options.UseParallel
                pool = DenseHeightSweep.ensureThreadPool;
                numberOfWorkers = DenseHeightSweep.resolveWorkerCount( ...
                    pool, options.NumWorkers);
                if options.MaximumPendingTiles == 0
                    maximumPendingTiles = numberOfWorkers;
                else
                    maximumPendingTiles = options.MaximumPendingTiles;
                end
                execution = "threads-bounded-row-slab";
            else
                pool = gcp("nocreate");
                numberOfWorkers = 1;
                maximumPendingTiles = 1;
                execution = "serial-row-slab";
            end
            kernelOptions = struct( ...
                "StoreCostVolumes", true, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "WorkingPrecision", precision, ...
                "MinimumSupportFraction", ...
                options.MinimumSupportFraction);
            rowStarts = 1:options.RowSlabRows:nr;
            columnStarts = 1:options.TileColumns:nc;
            geometrySeconds = 0;
            samplingSeconds = 0;
            filterSeconds = 0;
            maximumBlockResultBytes = 0;
            maximumReturnedTileBytes = 0;
            timer = tic;

            for rowStart = rowStarts
                rows = rowStart:min( ...
                    rowStart + options.RowSlabRows - 1, nr);
                slabCost = nan( ...
                    numel(rows), nc, nl, precision);
                bounds = zeros(numel(columnStarts), 4);
                for k = 1:numel(columnStarts)
                    bounds(k, :) = [rows(1), rows(end), ...
                        columnStarts(k), ...
                        min(columnStarts(k) ...
                        + options.TileColumns - 1, nc)];
                end
                pending = min(maximumPendingTiles, size(bounds, 1));
                for batchStart = 1:pending:size(bounds, 1)
                    ids = batchStart:min( ...
                        batchStart + pending - 1, size(bounds, 1));
                    tiles = cell(numel(ids), 1);
                    if options.UseParallel
                        futures = parallel.FevalFuture.empty;
                        try
                            for k = 1:numel(ids)
                                futures(end + 1) = parfeval(pool, ...
                                    @DenseHeightSweep.evaluateDenseZnccTile, 1, ...
                                    obj.CostCurve, bounds(ids(k), :), ...
                                    z, kernelOptions); %#ok<AGROW>
                            end
                            for k = 1:numel(ids)
                                [completed, tile] = fetchNext(futures);
                                tiles{completed} = tile;
                            end
                        catch exception
                            cancel(futures);
                            rethrow(exception)
                        end
                    else
                        for k = 1:numel(ids)
                            tiles{k} = ...
                                DenseHeightSweep.evaluateDenseZnccTile( ...
                                obj.CostCurve, bounds(ids(k), :), ...
                                z, kernelOptions);
                        end
                    end
                    returned = whos("tiles");
                    maximumReturnedTileBytes = max( ...
                        maximumReturnedTileBytes, returned.bytes);
                    for k = 1:numel(tiles)
                        tile = tiles{k};
                        b = tile.Bounds;
                        columns = b(3):b(4);
                        tileSize = [numel(rows), numel(columns)];
                        summary = tile.Summary;
                        height(rows, columns) = reshape( ...
                            summary.HeightMetres, tileSize);
                        valid(rows, columns) = reshape( ...
                            summary.Valid, tileSize);
                        labelIndex(rows, columns) = reshape( ...
                            summary.LabelIndex, tileSize);
                        best(rows, columns) = reshape( ...
                            summary.BestCost, tileSize);
                        second(rows, columns) = reshape( ...
                            summary.SecondBestCost, tileSize);
                        previous(rows, columns) = reshape( ...
                            summary.PreviousLabelCost, tileSize);
                        next(rows, columns) = reshape( ...
                            summary.NextLabelCost, tileSize);
                        margin(rows, columns) = reshape( ...
                            summary.CostMargin, tileSize);
                        curvature(rows, columns) = reshape( ...
                            summary.LocalCurvaturePerMetreSquared, tileSize);
                        validLabelCount(rows, columns) = reshape( ...
                            summary.ValidLabelCount, tileSize);
                        slabCost(:, columns, :) = reshape( ...
                            tile.CostVolume, [tileSize, nl]);
                        geometrySeconds = geometrySeconds ...
                            + tile.GeometrySeconds;
                        samplingSeconds = samplingSeconds ...
                            + tile.SamplingSeconds;
                        filterSeconds = filterSeconds + tile.FilterSeconds;
                        maximumBlockResultBytes = max( ...
                            maximumBlockResultBytes, ...
                            tile.MaximumBlockResultBytes);
                    end
                end
                store.writeRows(rows, slabCost);
            end
            elapsed = toc(timer);
            outputInfo = whos("height", "valid", "labelIndex", ...
                "best", "second", "previous", "next", "margin", ...
                "curvature", "validLabelCount");
            result = struct( ...
                "HeightLabelsMetres", z, ...
                "HeightMetres", height, ...
                "Valid", valid, ...
                "LabelIndex", labelIndex, ...
                "BestCost", best, ...
                "SecondBestCost", second, ...
                "PreviousLabelCost", previous, ...
                "NextLabelCost", next, ...
                "CostMargin", margin, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", validLabelCount, ...
                "ValidLabelFraction", validLabelCount ./ nl, ...
                "CostStore", store, ...
                "CostVolume", zeros([nr, nc, 0], precision), ...
                "StoreStatistics", store.statistics, ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", ...
                obj.CostCurve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                obj.CostCurve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Interpolation", ...
                "vectorized bilinear; all nonzero-weight samples required", ...
                "Runtime", struct( ...
                "EvaluationSeconds", elapsed, ...
                "GeometrySeconds", geometrySeconds, ...
                "BilinearSamplingSeconds", samplingSeconds, ...
                "LocalFilterSeconds", filterSeconds, ...
                "MaximumBlockResultBytes", maximumBlockResultBytes, ...
                "MaximumReturnedTileBytes", maximumReturnedTileBytes, ...
                "OutputArrayBytes", sum([outputInfo.bytes]), ...
                "RetainedSlabCount", 1, ...
                "RowSlabRows", min(options.RowSlabRows, nr), ...
                "TileColumns", min(options.TileColumns, nc), ...
                "Execution", execution, ...
                "NumWorkers", numberOfWorkers, ...
                "Precision", precision));
        end

        function tuning = tuneZnccOptimized(obj, z, options)
            %TUNEZNCCOPTIMIZED Tune bounded thread scheduling by machine.

            arguments
                obj (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeIncreasing, mustHaveThreeElements}
                options.WorkerCounts (1, :) double ...
                    {mustBeInteger, mustBePositive} = zeros(1, 0)
                options.Exhaustive (1, 1) logical = false
                options.Repetitions (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 2
                options.WarmupRuns (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 1
                options.Verbose (1, 1) logical = true
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
            end

            pool = DenseHeightSweep.ensureThreadPool;
            maximumWorkers = pool.NumWorkers;
            if isempty(options.WorkerCounts)
                if options.Exhaustive
                    workers = 1:maximumWorkers;
                else
                    powers = 2 .^ (0:floor(log2(maximumWorkers)));
                    workers = unique([powers, maximumWorkers]);
                end
            else
                workers = unique(options.WorkerCounts);
            end
            if any(workers > maximumWorkers)
                error("DenseHeightSweep:TooManyWorkers", ...
                    "WorkerCounts cannot exceed the thread pool size of %d.", ...
                    maximumWorkers);
            end
            products = ["LabelIndex", "BestCost", "Margin", ...
                "Curvature", "Observability"];
            reference = obj.runZnccOptimized(z, ...
                TileSize=options.TileSize, ...
                LabelBlockSize=options.LabelBlockSize, ...
                StoreCostVolumes=false, UseParallel=false, ...
                WorkingPrecision=options.WorkingPrecision, ...
                Products=products, ...
                MinimumSupportFraction=options.MinimumSupportFraction);
            elapsed = zeros(numel(workers), options.Repetitions);
            for workerIndex = 1:numel(workers)
                for warmup = 1:options.WarmupRuns
                    candidate = obj.runZnccOptimized(z, ...
                        TileSize=options.TileSize, ...
                        LabelBlockSize=options.LabelBlockSize, ...
                        StoreCostVolumes=false, UseParallel=true, ...
                        WorkingPrecision=options.WorkingPrecision, ...
                        NumWorkers=workers(workerIndex), ...
                        MaximumPendingTiles=workers(workerIndex), ...
                        Products=products, ...
                        MinimumSupportFraction= ...
                        options.MinimumSupportFraction);
                    if ~DenseHeightSweep.resultsEquivalent( ...
                            reference, candidate)
                        error("DenseHeightSweep:TuningMismatch", ...
                            "Optimized ZNCC thread tuning warm-up " ...
                            + "produced a result that does not match " ...
                            + "the serial reference.");
                    end
                end
                for repetition = 1:options.Repetitions
                    timer = tic;
                    candidate = obj.runZnccOptimized(z, ...
                        TileSize=options.TileSize, ...
                        LabelBlockSize=options.LabelBlockSize, ...
                        StoreCostVolumes=false, UseParallel=true, ...
                        WorkingPrecision=options.WorkingPrecision, ...
                        NumWorkers=workers(workerIndex), ...
                        MaximumPendingTiles=workers(workerIndex), ...
                        Products=products, ...
                        MinimumSupportFraction= ...
                        options.MinimumSupportFraction);
                    elapsed(workerIndex, repetition) = toc(timer);
                    if ~DenseHeightSweep.resultsEquivalent( ...
                            reference, candidate)
                        error("DenseHeightSweep:TuningMismatch", ...
                            "Optimized ZNCC thread tuning produced a " ...
                            + "result that does not match the serial reference.");
                    end
                    if options.Verbose
                        fprintf("Optimized ZNCC tuning: %d workers, " ...
                            + "repetition %d/%d, %.3f s\n", ...
                            workers(workerIndex), repetition, ...
                            options.Repetitions, ...
                            elapsed(workerIndex, repetition));
                    end
                end
            end
            medianSeconds = median(elapsed, 2);
            speedup = medianSeconds(1) ./ medianSeconds;
            pixelLabelsPerSecond = ...
                reference.Runtime.PixelLabelCount ./ medianSeconds;
            [~, fastest] = min(medianSeconds);
            results = table(workers(:), medianSeconds, speedup, ...
                pixelLabelsPerSecond, ...
                VariableNames=["Workers", "MedianSeconds", "Speedup", ...
                "PixelLabelsPerSecond"]);
            tuning = struct( ...
                "Results", results, ...
                "RecommendedWorkers", workers(fastest), ...
                "PoolWorkers", maximumWorkers, ...
                "Repetitions", options.Repetitions, ...
                "WarmupRuns", options.WarmupRuns, ...
                "TileCount", reference.Runtime.TileCount, ...
                "PixelLabelCount", reference.Runtime.PixelLabelCount, ...
                "TileSize", options.TileSize, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "WorkingPrecision", options.WorkingPrecision, ...
                "HeightLabelsMetres", z, ...
                "Execution", "bounded parfeval on parpool('threads')");
            if options.Verbose
                disp(results);
                fprintf("Recommended optimized ZNCC worker count: %d\n", ...
                    tuning.RecommendedWorkers);
            end
        end

        function tuning = tuneThreads(obj, z, options)
            %TUNETHREADS Benchmark exact tiled runs across thread counts.

            arguments
                obj (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeIncreasing, mustHaveThreeElements}
                options.WorkerCounts (1, :) double ...
                    {mustBeInteger, mustBePositive} = zeros(1, 0)
                options.Exhaustive (1, 1) logical = false
                options.Repetitions (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 2
                options.Verbose (1, 1) logical = true
                options.Channel (1, 1) string ...
                    {mustBeMember(options.Channel, ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", "HybridZnccSpin2T3"])} ...
                    = "HybridZnccSpin2T3"
                options.Channels (1, :) string ...
                    {mustBeNonempty, mustBeMember(options.Channels, ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", ...
                    "HybridZnccSpin2T3"])} = ...
                    ["Zncc", "Census", "NormalizedGradient", ...
                    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                    "Spin2T3", "Spin2T4", "HybridZnccSpin2T3"]
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 16
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-6
                options.RequireOrientationPreserving (1, 1) logical = true
            end

            pool = DenseHeightSweep.ensureThreadPool;
            maximumWorkers = pool.NumWorkers;
            if isempty(options.WorkerCounts)
                if options.Exhaustive
                    workers = 1:maximumWorkers;
                else
                    powers = 2 .^ (0:floor(log2(maximumWorkers)));
                    workers = unique([powers, maximumWorkers]);
                end
            else
                workers = unique(options.WorkerCounts);
            end
            if any(workers > maximumWorkers)
                error("DenseHeightSweep:TooManyWorkers", ...
                    "WorkerCounts cannot exceed the thread pool size of %d.", ...
                    maximumWorkers);
            end

            % One untimed run initializes code paths and supplies exact truth.
            reference = obj.runTiled(z, Channel=options.Channel, ...
                Channels=options.Channels, ...
                TileSize=options.TileSize, ...
                LabelBlockSize=options.LabelBlockSize, ...
                StoreCostVolumes=false, UseParallel=true, ...
                NumWorkers=workers(1), DeltaPixel=options.DeltaPixel, ...
                DeltaHeight=options.DeltaHeight, ...
                MinimumSupportFraction=options.MinimumSupportFraction, ...
                MinimumGradient=options.MinimumGradient, ...
                RequireOrientationPreserving= ...
                options.RequireOrientationPreserving);
            elapsed = zeros(numel(workers), options.Repetitions);
            tileCount = reference.Runtime.TileCount;
            pixelLabelCount = reference.Runtime.PixelLabelCount;
            for workerIndex = 1:numel(workers)
                for repetition = 1:options.Repetitions
                    timer = tic;
                    candidate = obj.runTiled(z, ...
                        Channel=options.Channel, ...
                        Channels=options.Channels, ...
                        TileSize=options.TileSize, ...
                        LabelBlockSize=options.LabelBlockSize, ...
                        StoreCostVolumes=false, UseParallel=true, ...
                        NumWorkers=workers(workerIndex), ...
                        DeltaPixel=options.DeltaPixel, ...
                        DeltaHeight=options.DeltaHeight, ...
                        MinimumSupportFraction= ...
                        options.MinimumSupportFraction, ...
                        MinimumGradient=options.MinimumGradient, ...
                        RequireOrientationPreserving= ...
                        options.RequireOrientationPreserving);
                    elapsed(workerIndex, repetition) = toc(timer);
                    if ~DenseHeightSweep.resultsEquivalent( ...
                            reference, candidate)
                        error("DenseHeightSweep:TuningMismatch", ...
                            ["Thread-count tuning produced a result that " ...
                            "does not match the reference."]);
                    end
                    if options.Verbose
                        fprintf("Dense thread tuning: %d workers, " ...
                            + "repetition %d/%d, %.3f s\n", ...
                            workers(workerIndex), repetition, ...
                            options.Repetitions, ...
                            elapsed(workerIndex, repetition));
                    end
                end
            end

            medianSeconds = median(elapsed, 2);
            speedup = medianSeconds(1) ./ medianSeconds;
            tilesPerSecond = tileCount ./ medianSeconds;
            pixelLabelsPerSecond = pixelLabelCount ./ medianSeconds;
            [~, fastest] = min(medianSeconds);
            results = table(workers(:), medianSeconds, speedup, ...
                tilesPerSecond, pixelLabelsPerSecond, ...
                VariableNames=["Workers", "MedianSeconds", "Speedup", ...
                "TilesPerSecond", "PixelLabelsPerSecond"]);
            tuning = struct( ...
                "Results", results, ...
                "RecommendedWorkers", workers(fastest), ...
                "PoolWorkers", maximumWorkers, ...
                "Repetitions", options.Repetitions, ...
                "TileCount", tileCount, ...
                "PixelLabelCount", pixelLabelCount, ...
                "Channel", options.Channel, ...
                "ComputedChannels", reference.ComputedChannels, ...
                "TileSize", options.TileSize, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "HeightLabelsMetres", z);
            if options.Verbose
                disp(results);
                fprintf("Recommended dense worker count: %d\n", ...
                    tuning.RecommendedWorkers);
            end
        end

        function result = projectHeightMap(obj, height, validMask, options)
            %PROJECTHEIGHTMAP Convert a metre-valued height map through w(p,Z).
            % Traceability: algo/main.tex Algorithm 1, lines 16-18.

            arguments
                obj (1, 1) DenseHeightSweep
                height (:, :) double ...
                    {mustMatchReferenceSize(height, obj)}
                validMask (:, :) logical ...
                    {mustMatchReferenceSize(validMask, obj)}
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.Products (1, :) string ...
                    {mustBeProjectionProducts} = ...
                    ["Correspondence", "Observability", ...
                    "ValidityDiagnostics"]
            end

            imageSize = size(height);
            products = unique(options.Products, "stable");
            needCorrespondence = any(products == "Correspondence");
            needObservability = any(products == "Observability");
            needDiagnostics = any(products == "ValidityDiagnostics");
            inputValid = validMask & isfinite(height);
            valid = false(imageSize);
            projectionValid = DenseHeightSweep.optionalArray( ...
                imageSize, needDiagnostics, false, "logical");
            inside = DenseHeightSweep.optionalArray( ...
                imageSize, needDiagnostics, false, "logical");
            derivativeValid = DenseHeightSweep.optionalArray( ...
                imageSize, needDiagnostics, false, "logical");
            if needCorrespondence
                correspondence = nan([imageSize, 2]);
            else
                correspondence = zeros([imageSize, 0]);
            end
            observability = DenseHeightSweep.optionalArray( ...
                imageSize, needObservability, NaN);
            index = find(inputValid);
            if ~isempty(index)
                [y, x] = ind2sub(imageSize, index);
                p = [x, y];
                z = height(index);
                [w, vp, vi] = obj.CostCurve.Geometry.warp(p, z);
                [~, kappa, vd] = ...
                    obj.CostCurve.Geometry.heightDerivative( ...
                    p, z, DeltaHeight=options.DeltaHeight);
                keep = vp & vi & vd;
                valid(index(keep)) = true;
                if needDiagnostics
                    projectionValid(index) = vp;
                    inside(index) = vi;
                    derivativeValid(index) = vd;
                end
                if needCorrespondence
                    wx = correspondence(:, :, 1);
                    wy = correspondence(:, :, 2);
                    wx(index(keep)) = w(keep, 1);
                    wy(index(keep)) = w(keep, 2);
                    correspondence(:, :, 1) = wx;
                    correspondence(:, :, 2) = wy;
                end
                if needObservability
                    observability(index(keep)) = kappa(keep);
                end
            end
            outputHeight = height;
            outputHeight(~valid) = NaN;
            result = struct( ...
                "HeightMetres", outputHeight, ...
                "CorrespondenceXY", correspondence, ...
                "ObservabilityPixelsPerMetre", observability, ...
                "InputValid", DenseHeightSweep.optionalValue( ...
                inputValid, needDiagnostics), ...
                "ProjectionValid", projectionValid, ...
                "InsideMovingImage", inside, ...
                "DerivativeValid", derivativeValid, ...
                "Valid", valid, ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", ...
                obj.CostCurve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                obj.CostCurve.Geometry.ReferenceCamera.ElevationDatum);
        end
    end

    methods (Static, Access = private)
        function result = evaluateTile(costCurve, bounds, z, options, names)
            rowStart = bounds(1);
            rowEnd = bounds(2);
            columnStart = bounds(3);
            columnEnd = bounds(4);
            [yy, xx] = ndgrid(rowStart:rowEnd, columnStart:columnEnd);
            p = [xx(:), yy(:)];
            nt = size(p, 1);
            nl = numel(z);
            state = DenseHeightSweep.initializeTileState(nt, names);
            costVolumeByChannel = struct;
            if options.StoreCostVolumes
                for k = 1:numel(names)
                    costVolumeByChannel.(names{k}) = nan(nt, nl);
                end
            end
            maximumBlockResultBytes = 0;
            operationSeconds = zeros(1, 5);
            operationCounts = zeros(1, 9);

            for labelStart = 1:options.LabelBlockSize:nl
                labelEnd = min(labelStart + options.LabelBlockSize - 1, nl);
                ids = labelStart:labelEnd;
                block = costCurve.evaluate(p, z(ids), ...
                    DeltaPixel=options.DeltaPixel, ...
                    DeltaHeight=options.DeltaHeight, ...
                    MinimumSupportFraction=options.MinimumSupportFraction, ...
                    MinimumGradient=options.MinimumGradient, ...
                    RequireOrientationPreserving= ...
                    options.RequireOrientationPreserving, ...
                    ProfileOperations=options.ProfileOperations, ...
                    Channels=string(names));
                blockInfo = whos("block");
                maximumBlockResultBytes = max( ...
                    maximumBlockResultBytes, blockInfo.bytes);
                operationSeconds = operationSeconds ...
                    + block.Profiling.OperationSeconds;
                operationCounts = operationCounts ...
                    + block.Profiling.OperationCounts;
                for k = 1:numel(names)
                    name = names{k};
                    if options.StoreCostVolumes
                        costVolumeByChannel.(name)(:, ids) = ...
                            block.Costs.(name);
                    end
                    [state.ChannelBestCost.(name), ...
                        state.ChannelBestIndex.(name)] = ...
                        DenseHeightSweep.updateBest( ...
                        state.ChannelBestCost.(name), ...
                        state.ChannelBestIndex.(name), ...
                        block.Costs.(name), ids);
                end
                primary = block.Costs.(char(options.Channel));
                for j = 1:numel(ids)
                    state = DenseHeightSweep.updatePrimary( ...
                        state, primary(:, j), ids(j));
                end
            end

            selectedByChannel = struct;
            for k = 1:numel(names)
                name = names{k};
                index = state.ChannelBestIndex.(name);
                h = nan(nt, 1);
                valid = index > 0;
                h(valid) = z(index(valid));
                selectedByChannel.(name) = h;
            end
            result = struct( ...
                "Bounds", bounds, ...
                "Summary", DenseHeightSweep.summarizeTile(state, z), ...
                "SelectedHeightByChannel", selectedByChannel, ...
                "CostVolumeByChannel", costVolumeByChannel, ...
                "MaximumBlockResultBytes", maximumBlockResultBytes, ...
                "OperationSeconds", operationSeconds, ...
                "OperationCounts", operationCounts);
        end

        function result = evaluateDenseZnccTile( ...
                costCurve, bounds, z, options)
            radius = costCurve.Reference.IntegrationRadius;
            rows = (bounds(1) - radius):(bounds(2) + radius);
            columns = (bounds(3) - radius):(bounds(4) + radius);
            [yy, xx] = ndgrid(rows, columns);
            p = [xx(:), yy(:)];
            extendedSize = [numel(rows), numel(columns)];
            coreSize = [bounds(2) - bounds(1) + 1, ...
                bounds(4) - bounds(3) + 1];
            ne = prod(extendedSize);
            nt = prod(coreSize);
            nl = numel(z);

            samplingTimer = tic;
            [reference, referenceValid] = ...
                HeightSweepArrayKernels.bilinear( ...
                costCurve.Reference.Image, p, ...
                ValidMask=costCurve.Reference.InputValid);
            samplingSeconds = toc(samplingTimer);
            reference = cast(reshape(reference, extendedSize), ...
                options.WorkingPrecision);
            referenceValid = reshape(referenceValid, extendedSize);
            state = DenseHeightSweep.initializeTileState( ...
                nt, {'Zncc'}, options.WorkingPrecision);
            if options.StoreCostVolumes
                costVolume = nan(nt, nl, options.WorkingPrecision);
            else
                costVolume = zeros(nt, 0, options.WorkingPrecision);
            end
            geometrySeconds = 0;
            filterSeconds = 0;
            warpCalls = 0;
            maximumBlockResultBytes = 0;

            for labelStart = 1:options.LabelBlockSize:nl
                labelEnd = min( ...
                    labelStart + options.LabelBlockSize - 1, nl);
                ids = labelStart:labelEnd;
                nb = numel(ids);
                pb = repmat(p, nb, 1);
                zb = repelem(reshape(z(ids), [], 1), ne);
                geometryTimer = tic;
                [w, warpValid] = costCurve.Geometry.warp(pb, zb);
                geometrySeconds = geometrySeconds + toc(geometryTimer);
                warpCalls = warpCalls + 1;

                samplingTimer = tic;
                [moving, movingValid] = ...
                    HeightSweepArrayKernels.bilinear( ...
                    costCurve.Moving.Image, w, ...
                    ValidMask=costCurve.Moving.InputValid);
                samplingSeconds = samplingSeconds + toc(samplingTimer);
                moving = cast(reshape(moving, [extendedSize, nb]), ...
                    options.WorkingPrecision);
                jointValid = reshape( ...
                    warpValid & movingValid, [extendedSize, nb]) ...
                    & referenceValid;

                filterTimer = tic;
                costBlock = HeightSweepArrayKernels.maskedZncc( ...
                    reference, moving, jointValid, ...
                    costCurve.Reference.IntegrationKernel, ...
                    MinimumSupportFraction= ...
                    options.MinimumSupportFraction, ...
                    Epsilon=costCurve.Reference.Epsilon);
                filterSeconds = filterSeconds + toc(filterTimer);
                c = reshape(costBlock, nt, nb);
                blockInfo = whos("pb", "zb", "w", "warpValid", ...
                    "moving", "movingValid", "jointValid", ...
                    "costBlock", "c");
                maximumBlockResultBytes = max( ...
                    maximumBlockResultBytes, sum([blockInfo.bytes]));
                if options.StoreCostVolumes
                    costVolume(:, ids) = c;
                end
                [state.ChannelBestCost.Zncc, ...
                    state.ChannelBestIndex.Zncc] = ...
                    DenseHeightSweep.updateBest( ...
                    state.ChannelBestCost.Zncc, ...
                    state.ChannelBestIndex.Zncc, c, ids);
                for k = 1:nb
                    state = DenseHeightSweep.updatePrimary( ...
                        state, c(:, k), ids(k));
                end
            end

            result = struct( ...
                "Bounds", bounds, ...
                "Summary", DenseHeightSweep.summarizeTile(state, z), ...
                "CostVolume", costVolume, ...
                "GeometrySeconds", geometrySeconds, ...
                "SamplingSeconds", samplingSeconds, ...
                "FilterSeconds", filterSeconds, ...
                "WarpCalls", warpCalls, ...
                "WarpPointEvaluations", ne .* nl, ...
                "BilinearLocations", ne .* (1 + nl), ...
                "LocalFilterOutputSamples", nt .* nl, ...
                "MaximumBlockResultBytes", maximumBlockResultBytes);
        end

        function result = evaluateDenseT3Tile( ...
                costCurve, bounds, z, options)
            radius = costCurve.Reference.IntegrationRadius;
            rows = (bounds(1) - radius):(bounds(2) + radius);
            columns = (bounds(3) - radius):(bounds(4) + radius);
            [yy, xx] = ndgrid(rows, columns);
            p = [xx(:), yy(:)];
            extendedSize = [numel(rows), numel(columns)];
            coreSize = [bounds(2) - bounds(1) + 1, ...
                bounds(4) - bounds(3) + 1];
            ne = prod(extendedSize);
            nt = prod(coreSize);
            nl = numel(z);
            precision = options.WorkingPrecision;

            samplingTimer = tic;
            [rgx, vrx] = HeightSweepArrayKernels.bilinear( ...
                costCurve.Reference.Gx, p, ...
                ValidMask=costCurve.Reference.GradientValid);
            [rgy, vry] = HeightSweepArrayKernels.bilinear( ...
                costCurve.Reference.Gy, p, ...
                ValidMask=costCurve.Reference.GradientValid);
            samplingSeconds = toc(samplingTimer);
            reference = complex(cast(rgx, precision), cast(rgy, precision));
            referenceValid = vrx & vry ...
                & abs(reference) >= options.MinimumGradient;
            reference = reshape(reference, extendedSize);
            referenceValid = reshape(referenceValid, extendedSize);
            state = DenseHeightSweep.initializeTileState( ...
                nt, {'Spin2T3'}, precision);
            bestConfidence = nan(nt, 1, precision);
            bestSupport = nan(nt, 1, precision);
            if options.StoreCostVolumes
                costVolume = nan(nt, nl, precision);
            else
                costVolume = zeros(nt, 0, precision);
            end
            geometrySeconds = 0;
            filterSeconds = 0;
            maximumBlockResultBytes = 0;

            for labelStart = 1:options.LabelBlockSize:nl
                labelEnd = min( ...
                    labelStart + options.LabelBlockSize - 1, nl);
                ids = labelStart:labelEnd;
                nb = numel(ids);
                pb = repmat(p, nb, 1);
                zb = repelem(reshape(z(ids), [], 1), ne);
                geometryTimer = tic;
                [w, warpValid] = costCurve.Geometry.warp(pb, zb);
                [a, jacobianValid] = costCurve.Geometry.warpJacobian( ...
                    pb, zb, DeltaPixel=options.DeltaPixel);
                geometrySeconds = geometrySeconds + toc(geometryTimer);

                samplingTimer = tic;
                [mgx, vx] = HeightSweepArrayKernels.bilinear( ...
                    costCurve.Moving.Gx, w, ...
                    ValidMask=costCurve.Moving.GradientValid);
                [mgy, vy] = HeightSweepArrayKernels.bilinear( ...
                    costCurve.Moving.Gy, w, ...
                    ValidMask=costCurve.Moving.GradientValid);
                samplingSeconds = samplingSeconds + toc(samplingTimer);
                mgx = cast(mgx, precision);
                mgy = cast(mgy, precision);
                h = HeightSweepArrayKernels.transportGradient(mgx, mgy, a);
                detA = a(:, 1, 1) .* a(:, 2, 2) ...
                    - a(:, 1, 2) .* a(:, 2, 1);
                orientationValid = ...
                    ~options.RequireOrientationPreserving | detA > 0;
                movingValid = warpValid & jacobianValid & vx & vy ...
                    & orientationValid & abs(h) >= options.MinimumGradient;
                h = reshape(h, [extendedSize, nb]);
                movingValid = reshape( ...
                    movingValid, [extendedSize, nb]);

                filterTimer = tic;
                [costBlock, confidenceBlock, ~, supportBlock] = ...
                    HeightSweepArrayKernels.spin2T3( ...
                    reference, referenceValid, h, movingValid, ...
                    costCurve.Reference.IntegrationKernel, ...
                    MinimumSupportFraction= ...
                    options.MinimumSupportFraction, ...
                    Epsilon=costCurve.Reference.Epsilon);
                filterSeconds = filterSeconds + toc(filterTimer);
                c = reshape(costBlock, nt, nb);
                cf = reshape(confidenceBlock, nt, nb);
                sp = reshape(supportBlock, nt, nb);
                blockInfo = whos("pb", "zb", "w", "a", ...
                    "mgx", "mgy", "h", "movingValid", ...
                    "costBlock", "confidenceBlock", "supportBlock", "c");
                maximumBlockResultBytes = max( ...
                    maximumBlockResultBytes, sum([blockInfo.bytes]));
                if options.StoreCostVolumes
                    costVolume(:, ids) = c;
                end
                for k = 1:nb
                    better = isfinite(c(:, k)) ...
                        & c(:, k) < state.BestCost;
                    bestConfidence(better) = cf(better, k);
                    bestSupport(better) = sp(better, k);
                    state = DenseHeightSweep.updatePrimary( ...
                        state, c(:, k), ids(k));
                end
                [state.ChannelBestCost.Spin2T3, ...
                    state.ChannelBestIndex.Spin2T3] = ...
                    DenseHeightSweep.updateBest( ...
                    state.ChannelBestCost.Spin2T3, ...
                    state.ChannelBestIndex.Spin2T3, c, ids);
            end

            result = struct( ...
                "Bounds", bounds, ...
                "Summary", DenseHeightSweep.summarizeTile(state, z), ...
                "BestConfidence", bestConfidence, ...
                "BestSupport", bestSupport, ...
                "CostVolume", costVolume, ...
                "GeometrySeconds", geometrySeconds, ...
                "SamplingSeconds", samplingSeconds, ...
                "FilterSeconds", filterSeconds, ...
                "MaximumBlockResultBytes", maximumBlockResultBytes);
        end
    end

    methods (Static, Access = private)
        function result = summarize(cost, z)
            n = size(cost, 1);
            nl = numel(z);
            finiteCost = isfinite(cost);
            validLabelCount = sum(finiteCost, 2);
            sortable = cost;
            sortable(~finiteCost) = Inf;
            [sorted, order] = sort(sortable, 2, "ascend");
            best = sorted(:, 1);
            second = sorted(:, 2);
            labelIndex = order(:, 1);
            valid = validLabelCount > 0 & isfinite(best);
            best(~valid) = NaN;
            second(validLabelCount < 2 | ~isfinite(second)) = NaN;
            labelIndex(~valid) = 0;
            height = nan(n, 1);
            height(valid) = z(labelIndex(valid));
            margin = second - best;

            curvature = nan(n, 1);
            previous = nan(n, 1);
            next = nan(n, 1);
            interior = valid & labelIndex > 1 & labelIndex < nl;
            row = find(interior);
            centerIndex = sub2ind([n, nl], row, labelIndex(interior));
            previousIndex = sub2ind( ...
                [n, nl], row, labelIndex(interior) - 1);
            nextIndex = sub2ind( ...
                [n, nl], row, labelIndex(interior) + 1);
            previous(row) = cost(previousIndex);
            next(row) = cost(nextIndex);
            neighborValid = isfinite(cost(previousIndex)) ...
                & isfinite(cost(centerIndex)) & isfinite(cost(nextIndex));
            row = row(neighborValid);
            centerIndex = centerIndex(neighborValid);
            previousIndex = previousIndex(neighborValid);
            nextIndex = nextIndex(neighborValid);
            kc = labelIndex(row);
            hm = reshape(z(kc) - z(kc - 1), [], 1);
            hp = reshape(z(kc + 1) - z(kc), [], 1);
            curvature(row) = 2 .* ( ...
                cost(previousIndex) ./ (hm .* (hm + hp)) ...
                - cost(centerIndex) ./ (hm .* hp) ...
                + cost(nextIndex) ./ (hp .* (hm + hp)));

            result = struct( ...
                "HeightMetres", height, "Valid", valid, ...
                "LabelIndex", labelIndex, "BestCost", best, ...
                "SecondBestCost", second, "CostMargin", margin, ...
                "PreviousLabelCost", previous, ...
                "NextLabelCost", next, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", validLabelCount, ...
                "ValidLabelFraction", validLabelCount ./ nl);
        end

        function names = channelNames()
            names = {"Zncc", "Census", "NormalizedGradient", ...
                "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                "Spin2T3", "Spin2T4", "HybridZnccSpin2T3"};
        end

        function state = initializeTileState(n, names, precision)
            if nargin < 3
                precision = "double";
            end
            channelBestCost = struct;
            channelBestIndex = struct;
            for k = 1:numel(names)
                channelBestCost.(names{k}) = inf(n, 1, precision);
                channelBestIndex.(names{k}) = zeros(n, 1);
            end
            state = struct( ...
                "BestCost", inf(n, 1, precision), ...
                "SecondBestCost", inf(n, 1, precision), ...
                "BestIndex", zeros(n, 1), ...
                "PreviousLabelCost", nan(n, 1, precision), ...
                "PreviousBestCost", nan(n, 1, precision), ...
                "NextBestCost", nan(n, 1, precision), ...
                "ValidLabelCount", zeros(n, 1), ...
                "ChannelBestCost", channelBestCost, ...
                "ChannelBestIndex", channelBestIndex);
        end

        function [best, index] = updateBest(best, index, cost, ids)
            for j = 1:numel(ids)
                c = cost(:, j);
                better = isfinite(c) & c < best;
                best(better) = c(better);
                index(better) = ids(j);
            end
        end

        function state = updatePrimary(state, c, j)
            finite = isfinite(c);
            state.ValidLabelCount = state.ValidLabelCount + finite;
            next = state.BestIndex == j - 1;
            state.NextBestCost(next) = c(next);
            better = finite & c < state.BestCost;
            between = finite & ~better & c < state.SecondBestCost;
            state.SecondBestCost(better) = state.BestCost(better);
            state.SecondBestCost(between) = c(between);
            state.BestCost(better) = c(better);
            state.BestIndex(better) = j;
            state.PreviousBestCost(better) = ...
                state.PreviousLabelCost(better);
            state.NextBestCost(better) = NaN;
            state.PreviousLabelCost = c;
        end

        function result = summarizeTile(state, z)
            valid = state.BestIndex > 0 & isfinite(state.BestCost);
            best = state.BestCost;
            second = state.SecondBestCost;
            best(~valid) = NaN;
            second(~isfinite(second)) = NaN;
            height = nan(size(best));
            height(valid) = z(state.BestIndex(valid));
            curvature = nan(size(best), "like", best);
            interior = valid & state.BestIndex > 1 ...
                & state.BestIndex < numel(z) ...
                & isfinite(state.PreviousBestCost) ...
                & isfinite(state.NextBestCost);
            k = state.BestIndex(interior);
            hm = cast(reshape(z(k) - z(k - 1), [], 1), "like", best);
            hp = cast(reshape(z(k + 1) - z(k), [], 1), "like", best);
            curvature(interior) = cast(2, "like", best) .* ( ...
                state.PreviousBestCost(interior) ./ (hm .* (hm + hp)) ...
                - best(interior) ./ (hm .* hp) ...
                + state.NextBestCost(interior) ./ (hp .* (hm + hp)));
            result = struct( ...
                "HeightMetres", height, "Valid", valid, ...
                "LabelIndex", state.BestIndex, "BestCost", best, ...
                "SecondBestCost", second, ...
                "CostMargin", second - best, ...
                "PreviousLabelCost", state.PreviousBestCost, ...
                "NextLabelCost", state.NextBestCost, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", state.ValidLabelCount);
        end

        function pool = ensureThreadPool()
            pool = gcp("nocreate");
            if isempty(pool)
                pool = parpool("threads");
            elseif ~isa(pool, "parallel.ThreadPool")
                error("DenseHeightSweep:ThreadPoolRequired", ...
                    ["DenseHeightSweep requires parpool('threads'). " ...
                    "Close the existing process pool explicitly first."]);
            end
        end

        function n = resolveWorkerCount(pool, requested)
            if requested == 0
                n = pool.NumWorkers;
            else
                n = requested;
            end
            if n > pool.NumWorkers
                error("DenseHeightSweep:TooManyWorkers", ...
                    "NumWorkers cannot exceed the thread pool size of %d.", ...
                    pool.NumWorkers);
            end
        end

        function groups = groupIdenticalBands(plan, enabled, maximumTiles)
            %GROUPIDENTICALBANDS Merge adjacent equal-grid tiles by row.
            % A merged band evaluates each physical height plane once across
            % the combined core and removes duplicate ZNCC halos at internal
            % tile seams. Different physical label vectors never merge.
            % Traceability: implementation plan C1 milestone 5.
            if ~enabled
                groups = arrayfun(@(k) k, (1:height(plan)).', ...
                    UniformOutput=false);
                return
            end
            rowBounds = unique( ...
                [plan.RowStart, plan.RowEnd], "rows", "sorted");
            groups = cell(0, 1);
            for r = 1:size(rowBounds, 1)
                ids = find(plan.RowStart == rowBounds(r, 1) ...
                    & plan.RowEnd == rowBounds(r, 2));
                [~, order] = sort(plan.ColumnStart(ids));
                ids = reshape(ids(order), 1, []);
                current = ids(1);
                for k = 2:numel(ids)
                    previous = current(end);
                    id = ids(k);
                    adjacent = plan.ColumnEnd(previous) + 1 ...
                        == plan.ColumnStart(id);
                    sameLabels = isequal( ...
                        plan.HeightLabelsMetres{previous}, ...
                        plan.HeightLabelsMetres{id});
                    if adjacent && sameLabels ...
                            && numel(current) < maximumTiles
                        current(end + 1) = id; %#ok<AGROW>
                    else
                        groups{end + 1, 1} = current; %#ok<AGROW>
                        current = id;
                    end
                end
                groups{end + 1, 1} = current; %#ok<AGROW>
            end
        end

        function indices = validateTileStoreRequest( ...
                store, plan, imageSize, precision, replace)
            if store.Precision ~= precision
                error("DenseHeightSweep:TileStorePrecisionMismatch", ...
                    "Cost-store and requested working precision must match.");
            end
            storePlan = store.Plan;
            [found, indices] = ismember(plan.Tile, storePlan.Tile);
            if ~all(found)
                error("DenseHeightSweep:TileStoreIdentifierMismatch", ...
                    "Every requested tile must exist in the cost-store plan.");
            end
            expected = storePlan(indices, :);
            if any(plan.RowStart ~= expected.RowStart) ...
                    || any(plan.RowEnd ~= expected.RowEnd) ...
                    || any(plan.ColumnStart ~= expected.ColumnStart) ...
                    || any(plan.ColumnEnd ~= expected.ColumnEnd) ...
                    || max(storePlan.RowEnd) ~= imageSize(1) ...
                    || max(storePlan.ColumnEnd) ~= imageSize(2)
                error("DenseHeightSweep:TileStoreBoundsMismatch", ...
                    "Cost-store tile cores must match the reference and request.");
            end
            stats = store.statistics;
            if replace
                if ~stats.Complete
                    error("DenseHeightSweep:IncompleteTileStoreReplacement", ...
                        "Replacement requires a complete initial tile store.");
                end
            elseif stats.WrittenTileCount ~= 0 ...
                    || height(plan) ~= height(storePlan) ...
                    || any(indices(:) ~= (1:height(storePlan)).') ...
                    || any(plan.LabelCount ~= storePlan.LabelCount) ...
                    || ~all(cellfun(@isequal, plan.HeightLabelsMetres, ...
                    storePlan.HeightLabelsMetres))
                error("DenseHeightSweep:TileStoreNotEmptyOrMismatched", ...
                    "Initial generation requires an empty, identical full plan.");
            end
        end

        function stats = optionalTileStoreStatistics(store)
            if isempty(store)
                stats = struct;
            else
                stats = store.statistics;
            end
        end

        function a = optionalArray(imageSize, requested, fill, precision)
            if nargin < 4
                precision = "double";
            end
            if requested
                a = repmat(cast(fill, precision), imageSize);
            else
                a = zeros([imageSize, 0], precision);
            end
        end

        function a = optionalValue(a, requested)
            if ~requested
                a = zeros([size(a), 0], "like", a);
            end
        end

        function fraction = optionalFraction(count, requested, labelCount)
            if requested
                fraction = count ./ labelCount;
            else
                fraction = zeros(size(count));
            end
        end

        function result = optionalCostStruct(cost, requested, name)
            if requested
                result = struct;
                result.(name) = cost;
            else
                result = struct;
            end
        end

        function equivalent = resultsEquivalent(a, b)
            equivalent = isequaln(a.HeightMetres, b.HeightMetres) ...
                && isequaln(a.CorrespondenceXY, b.CorrespondenceXY) ...
                && isequal(a.Valid, b.Valid) ...
                && isequaln(a.BestCost, b.BestCost) ...
                && isequaln(a.CostMargin, b.CostMargin) ...
                && isequaln(a.LocalCurvaturePerMetreSquared, ...
                b.LocalCurvaturePerMetreSquared) ...
                && isequaln(a.SelectedHeightByChannel, ...
                b.SelectedHeightByChannel);
        end
    end
end

function mustBeDenseZnccProducts(products)
names = ["LabelIndex", "BestCost", "SecondBestCost", ...
    "NeighborCosts", "Margin", "Curvature", "ValidLabelCount", ...
    "Observability", "Correspondence", "SelectedHeightByChannel"];
mustBeMember(products, names);
end

function mustBePlannedZnccProducts(products)
names = ["TileIndex", "LabelCount", "LabelIndex", "BestCost", ...
    "SecondBestCost", "NeighborCosts", "Margin", "Curvature", ...
    "ValidLabelCount", "Observability", "Correspondence", ...
    "SelectedHeightByChannel"];
mustBeMember(products, names);
if numel(unique(products)) ~= numel(products)
    error("DenseHeightSweep:DuplicatePlannedProduct", ...
        "Planned ZNCC products must not contain duplicate names.");
end
end

function mustBeProjectionProducts(products)
mustBeMember(products, ...
    ["Correspondence", "Observability", "ValidityDiagnostics"]);
if numel(unique(products)) ~= numel(products)
    error("DenseHeightSweep:DuplicateProjectionProduct", ...
        "Projection products must not contain duplicate names.");
end
end

function mustBeOptionalHeightTileStore(store)
if ~isempty(store) && ~isa(store, "HeightTileStore")
    error("DenseHeightSweep:InvalidTileStore", ...
        "CostStore must be empty or a HeightTileStore.");
end
end

function mustBePlannedZnccTiles(plan)
required = ["Tile", "RowStart", "RowEnd", "ColumnStart", ...
    "ColumnEnd", "LabelCount", "HeightLabelsMetres"];
if isempty(plan) || ~all(ismember(required, string(plan.Properties.VariableNames)))
    error("DenseHeightSweep:InvalidTilePlan", ...
        "Tile plan must be nonempty and contain the required variables.");
end
integerValues = [plan.Tile; plan.RowStart; plan.RowEnd; ...
    plan.ColumnStart; plan.ColumnEnd; plan.LabelCount];
if any(~isfinite(integerValues)) || any(integerValues < 1) ...
        || any(integerValues ~= fix(integerValues)) ...
        || any(plan.RowEnd < plan.RowStart) ...
        || any(plan.ColumnEnd < plan.ColumnStart) ...
        || numel(unique(plan.Tile)) ~= height(plan)
    error("DenseHeightSweep:InvalidTilePlan", ...
        "Tile identifiers, bounds, and label counts must be valid integers.");
end
if ~iscell(plan.HeightLabelsMetres) ...
        || any(cellfun(@(z) ~isa(z, "double") || ~isrow(z) ...
        || numel(z) < 3 || any(~isfinite(z)) ...
        || any(diff(z) <= 0), plan.HeightLabelsMetres)) ...
        || any(cellfun(@numel, plan.HeightLabelsMetres) ~= plan.LabelCount)
    error("DenseHeightSweep:InvalidTilePlan", ...
        "Each tile needs a finite, increasing double label row of LabelCount length.");
end
end

function mustBeDenseT3Products(products)
names = ["LabelIndex", "BestCost", "SecondBestCost", ...
    "NeighborCosts", "Margin", "Curvature", "ValidLabelCount", ...
    "Confidence", "Support", "Observability", "Correspondence"];
mustBeMember(products, names);
end

function mustHaveThreeElements(x)
if numel(x) < 3
    error("DenseHeightSweep:TooFewLabels", ...
        "At least three height labels are required for dense diagnostics.");
end
end

function mustBeIncreasing(x)
if any(diff(x) <= 0)
    error("DenseHeightSweep:LabelsNotIncreasing", ...
        "Height labels must be strictly increasing.");
end
end

function mustMatchReferenceSize(x, obj)
expected = obj.CostCurve.Geometry.ReferenceCamera.ImageSize;
if ~isequal(size(x), expected)
    error("DenseHeightSweep:MapSizeMismatch", ...
        "Height and validity maps must match the reference image size.");
end
end

function mustBeWritableZnccStore(store, obj, z)
imageSize = obj.CostCurve.Geometry.ReferenceCamera.ImageSize;
expected = [imageSize, numel(z)];
if ~isequal(store.Shape, expected)
    error("DenseHeightSweep:CostStoreSizeMismatch", ...
        "The ZNCC store must have size [rows,columns,labels].");
end
storedLabels = reshape(double( ...
    store.Metadata.HeightLabelsMetres), 1, []);
if ~isequal(z, storedLabels)
    error("DenseHeightSweep:CostStoreLabelMismatch", ...
        "The ZNCC store labels must exactly match the requested grid.");
end
stats = store.statistics;
if stats.WrittenRowCount ~= 0
    error("DenseHeightSweep:CostStoreNotEmpty", ...
        "The ZNCC store must be unwritten before generation.");
end
end
